window.PACTO.acts["reg-2016-1624"]={"label": "REGOLAMENTO (UE) 2016/1624 DEL PARLAMENTO EUROPEO E DEL CONSIGLIO", "short": "Reg. 2016/1624", "file": "ext-reg-2016-1624.html", "external": true, "version": "originale GU", "eurlex": "https://eur-lex.europa.eu/eli/reg/2016/1624/oj/ita", "articles": {"1": {"label": "Articolo 1", "heading": "Oggetto", "anchor": "art_1", "frags": [[null, "<p class=\"oj-normal\">Il presente regolamento istituisce una guardia di frontiera e costiera europea per garantire una gestione europea integrata delle frontiere esterne, allo scopo di gestire efficacemente l'attraversamento delle frontiere esterne. Ciò implica affrontare le sfide migratorie e le potenziali minacce future a tali frontiere, contribuendo così a lottare contro la criminalità grave di dimensione transfrontaliera, al fine di garantire un livello elevato di sicurezza interna nell'Unione, nel pieno rispetto dei diritti fondamentali e salvaguardando al contempo la libera circolazione delle persone al suo interno.</p>"]]}, "2": {"label": "Articolo 2", "heading": "Definizioni", "anchor": "art_2", "frags": [[null, "<p class=\"oj-normal\">Ai fini del presente regolamento si intende per:</p>"], [null, "<p class=\"oj-normal\">1)   <span class=\"oj-bold\">«frontiere esterne»</span>: le frontiere esterne quali definite all'articolo 2, punto 2, del regolamento (UE) 2016/399, a cui si applica il titolo II di tale regolamento;</p>"], [null, "<p class=\"oj-normal\">2)   <span class=\"oj-bold\">«controllo di frontiera»</span>: il controllo di frontiera ai sensi dell'articolo 2, punto 10, del regolamento (UE) 2016/399;</p>"], [null, "<p class=\"oj-normal\">3)   <span class=\"oj-bold\">«guardia di frontiera»</span>: la guardia di frontiera ai sensi dell'articolo 2, punto 14, del regolamento (UE) 2016/399;</p>"], [null, "<p class=\"oj-normal\">4)   <span class=\"oj-bold\">«squadre della guardia di frontiera e costiera europea»</span>: squadre di guardie di frontiera e altro personale competente degli Stati membri partecipanti, compresi guardie di frontiera e altro personale competente distaccati in qualità di esperti nazionali dagli Stati membri presso l'Agenzia europea della guardia di frontiera e costiera, da impiegare nelle operazioni congiunte e negli interventi rapidi alle frontiere, nonché nell'ambito delle squadre di sostegno per la gestione della migrazione;</p>"], [null, "<p class=\"oj-normal\">5)   <span class=\"oj-bold\">«Stato membro ospitante»</span>: lo Stato membro nel quale ha luogo o dal quale prende avvio un'operazione congiunta o un intervento rapido alle frontiere, un'operazione di rimpatrio o un intervento di rimpatrio, o nel quale è dispiegata una squadra di sostegno per la gestione della migrazione;</p>"], [null, "<p class=\"oj-normal\">6)   <span class=\"oj-bold\">«Stato membro di appartenenza»</span>: lo Stato membro al quale un membro delle squadre della guardia di frontiera e costiera europea che esercita le funzioni di guardia di frontiera o altre funzioni pertinenti appartiene;</p>"], [null, "<p class=\"oj-normal\">7)   <span class=\"oj-bold\">«Stato membro partecipante»</span>: lo Stato membro che partecipa a un'operazione congiunta, a un intervento rapido alle frontiere, a un'operazione o un intervento di rimpatrio o il dispiegamento di una squadra di sostegno per la gestione della migrazione, fornendo attrezzatura tecnica, guardie di frontiera e altro personale competente nell'ambito delle squadre della guardia di frontiera e costiera europea, nonché lo Stato membro che partecipa a operazioni di rimpatrio o interventi di rimpatrio fornendo attrezzatura tecnica o personale, diverso dallo Stato membro ospitante;</p>"], [null, "<p class=\"oj-normal\">8)   <span class=\"oj-bold\">«membri delle squadre»</span>: membri delle squadre della guardia di frontiera e costiera europea o di squadre di personale che assolve compiti attinenti al rimpatrio, che partecipano a operazioni di rimpatrio o interventi di rimpatrio;</p>"], [null, "<p class=\"oj-normal\">9)   <span class=\"oj-bold\">«squadre di sostegno per la gestione della migrazione»</span>: squadre di esperti che forniscono un rinforzo tecnico e operativo agli Stati membri nei punti di crisi e che sono composte da esperti degli Stati membri distaccati dall'Agenzia europea della guardia di frontiera e costiera e dall'Ufficio europeo di sostegno per l'asilo, nonché dall'Agenzia europea della guardia di frontiera e costiera, Europol o altre agenzie competenti dell'Unione;</p>"], [null, "<p class=\"oj-normal\">10)   <span class=\"oj-bold\">«punto di crisi»</span>: una zona in cui lo Stato membro ospitante, la Commissione, le agenzie dell'Unione competenti e gli Stati membri partecipanti cooperano allo scopo di gestire una sfida migratoria sproporzionata, reale o potenziale, caratterizzata da un aumento significativo del numero di migranti in arrivo alla frontiera esterna;</p>"], [null, "<p class=\"oj-normal\">11)   <span class=\"oj-bold\">«rimpatrio»</span>: il rimpatrio ai sensi dell'articolo 3, punto 3, della direttiva 2008/115/CE;</p>"], [null, "<p class=\"oj-normal\">12)   <span class=\"oj-bold\">«decisione di rimpatrio»</span>: una decisione amministrativa o giudiziaria ovvero un atto che attesti o dichiari l'illegalità del soggiorno di un cittadino di paesi terzi e imponga o attesti l'obbligo di rimpatrio, nel rispetto della direttiva 2008/115/CE;</p>"], [null, "<p class=\"oj-normal\">13)   <span class=\"oj-bold\">«rimpatriando»</span>: un cittadino di paese terzo il cui soggiorno è irregolare e che è soggetto a una decisione di rimpatrio adottata da uno Stato membro;</p>"], [null, "<p class=\"oj-normal\">14)   <span class=\"oj-bold\">«operazione di rimpatrio»</span>: un'operazione coordinata dall'Agenzia europea della guardia di frontiera costiera che implichi un rinforzo tecnico e operativo fornito da uno o più Stati membri, nell'ambito della quale rimpatriandi provenienti da uno o più Stati membri sono rimpatriati o in modo forzato o su base volontaria;</p>"], [null, "<p class=\"oj-normal\">15)   <span class=\"oj-bold\">«intervento di rimpatrio»</span>: un'attività dell'Agenzia europea della guardia di frontiera e costiera che fornisce agli Stati membri un'assistenza tecnica e operativa rafforzata mediante il dispiegamento negli Stati membri di squadre europee di intervento per il rimpatrio e l'organizzazione di operazioni di rimpatrio.</p>"], [null, "<p class=\"oj-normal\">16)   <span class=\"oj-bold\">«criminalità transfrontaliera»</span>: una forma grave di criminalità avente una dimensione transfrontaliera che ha luogo alle frontiere esterne o lungo le stesse o riferita alle frontiere esterne;</p>"]]}, "3": {"label": "Articolo 3", "heading": "Guardia di frontiera e costiera europea", "anchor": "art_3", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   L'Agenzia europea della guardia di frontiera e costiera («Agenzia») e le autorità nazionali degli Stati membri preposte alla gestione delle frontiere, comprese le guardie costiere nella misura in cui svolgono compiti di controllo di frontiera, costituiscono la guardia di frontiera e costiera europea.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   L'Agenzia, con decisione del consiglio di amministrazione e su proposta del direttore esecutivo, definisce una strategia operativa e tecnica per la gestione europea integrata delle frontiere. L'Agenzia tiene conto, ove giustificato, della situazione specifica degli Stati membri, in particolare della loro ubicazione geografica. Detta strategia deve essere conforme all'articolo 4. Essa promuove e sostiene l'attuazione della gestione europea integrata delle frontiere in tutti gli Stati membri.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Le autorità nazionali preposte alla gestione delle frontiere, comprese le guardie costiere nella misura in cui svolgono compiti di controllo di frontiera, definiscono le rispettive strategie nazionali per la gestione integrata delle frontiere. Dette strategie nazionali devono essere coerenti con l'articolo 4 e con la strategia di cui al paragrafo 2 del presente articolo.</p>\n</div>"]]}, "4": {"label": "Articolo 4", "heading": "Gestione europea integrata delle frontiere", "anchor": "art_4", "frags": [[null, "<p class=\"oj-normal\">La gestione europea integrata delle frontiere consiste dei seguenti elementi:</p>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">controllo di frontiera, comprese, se del caso, misure volte ad agevolare l'attraversamento legittimo delle frontiere e misure connesse alla prevenzione e all'individuazione della criminalità transfrontaliera, come il traffico di migranti, la tratta di esseri umani e il terrorismo, e misure relative all'orientamento in favore delle persone che necessitano di protezione internazionale o intendono presentare domanda in tal senso;</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">operazioni di ricerca e soccorso per le persone in pericolo in mare, avviate e svolte a norma del regolamento (UE) n. 656/2014 del Parlamento europeo e del Consiglio (<span class=\"oj-super oj-note-tag\">28</span>) e del diritto internazionale, che hanno luogo e sono avviate in situazioni che possono verificarsi nel corso di operazioni di sorveglianza delle frontiere in mare;</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">analisi dei rischi per la sicurezza interna e analisi delle minacce che possono pregiudicare il funzionamento o la sicurezza delle frontiere esterne;</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">cooperazione tra gli Stati membri sostenuta e coordinata dall'Agenzia;</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">e)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">cooperazione inter-agenzia tra le autorità nazionali di ciascuno Stato membro responsabili del controllo di frontiera o di altri compiti svolti alle frontiere e tra le istituzioni, gli organi, gli organismi e i servizi dell'Unione competenti, compreso lo scambio regolare di informazioni tramite gli strumenti di scambio di informazioni esistenti, ad esempio il sistema europeo di sorveglianza delle frontiere («EUROSUR») istituito dal regolamento (UE) n. 1052/2013 del Parlamento europeo e del Consiglio (<span class=\"oj-super oj-note-tag\">29</span>);</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">f)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">cooperazione con i paesi terzi nei settori contemplati dal presente regolamento, con particolare attenzione ai paesi del vicinato e ai paesi terzi che sono stati individuati tramite un'analisi dei rischi come paesi di origine e/o di transito dell'immigrazione illegale;</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">g)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">misure tecniche e operative nello spazio Schengen che sono connesse al controllo di frontiera e destinate ad affrontare meglio l'immigrazione illegale e a combattere la criminalità transfrontaliera;</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">h)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">rimpatrio di cittadini di paesi terzi soggetti a decisioni di rimpatrio adottate da uno Stato membro;</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">i)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">uso di tecnologie avanzate, compresi sistemi d'informazione su larga scala;</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">j)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">un meccanismo di controllo della qualità, in particolare il meccanismo di valutazione Schengen ed eventuali meccanismi nazionali, per garantire l'applicazione della normativa dell'Unione nel settore della gestione delle frontiere;</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">k)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">meccanismi di solidarietà, in particolare gli strumenti di finanziamento dell'Unione.</p>\n</td>\n</tr>\n</tbody>\n</table>"]]}, "5": {"label": "Articolo 5", "heading": "Responsabilità condivisa", "anchor": "art_5", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   La guardia di frontiera e costiera europea attua la gestione europea integrata delle frontiere come responsabilità condivisa tra l'Agenzia e le autorità nazionali preposte alla gestione delle frontiere, comprese le guardie costiere nella misura in cui svolgono operazioni di sorveglianza delle frontiere marittime e qualsiasi altro compito di controllo di frontiera. Gli Stati membri mantengono la responsabilità primaria nella gestione delle loro sezioni di frontiera esterna.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Ogni Stato membro provvede alla gestione delle proprie frontiere esterne, nel proprio interesse e nell'interesse comune di tutti gli Stati membri, nel pieno rispetto del diritto dell'Unione e secondo la strategia tecnica e operativa di cui all'articolo 3, paragrafo 2, in stretta cooperazione con l'Agenzia.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   L'Agenzia sostiene l'applicazione delle misure dell'Unione relative alla gestione delle frontiere esterne potenziando, valutando e coordinando gli interventi degli Stati membri nell'attuazione di tali misure, nonché nel rimpatrio.</p>\n</div>"]]}, "6": {"label": "Articolo 6", "heading": "Agenzia europea della guardia di frontiera e costiera", "anchor": "art_6", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Agenzia europea della guardia di frontiera e costiera è il nuovo nome dell'Agenzia europea per la gestione della cooperazione operativa alle frontiere esterne degli Stati membri dell'Unione europea, istituita dal regolamento (CE) n. 2007/2004. Le sue attività sono basate sul presente regolamento.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Per assicurare una gestione europea integrata delle frontiere coerente, l'Agenzia facilita e rende più efficace l'applicazione delle misure dell'Unione esistenti e future relative alla gestione delle frontiere esterne, in particolare il codice frontiere Schengen istituito dal regolamento (UE) 2016/399.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   L'Agenzia contribuisce a un'applicazione continua e uniforme della legislazione dell'Unione, compreso l'<span class=\"oj-italic\">acquis</span> dell'Unione in materia di diritti fondamentali, a tutte le frontiere esterne dell'Unione. Il suo contributo include lo scambio di buone prassi.</p>\n</div>"]]}, "7": {"label": "Articolo 7", "heading": "Responsabilità", "anchor": "art_7", "frags": [[null, "<p class=\"oj-normal\">L'Agenzia risponde del proprio operato al Parlamento europeo e al Consiglio, conformemente al presente regolamento.</p>"]]}, "8": {"label": "Articolo 8", "heading": "Compiti", "anchor": "art_8", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Al fine di contribuire a un controllo di frontiera e a un rimpatrio efficace, elevato e di livello uniforme, l'Agenzia svolge i seguenti compiti:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">monitora i flussi migratori e svolge analisi dei rischi su tutti gli aspetti della gestione integrata delle frontiere;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">effettua una valutazione della vulnerabilità, comprendente la verifica della capacità e della preparazione degli Stati membri a fronteggiare minacce e sfide alle frontiere esterne;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">monitora la gestione delle frontiere esterne tramite i funzionari di collegamento dell'Agenzia negli Stati membri;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">assiste gli Stati membri in circostanze che richiedono una maggiore assistenza tecnica e operativa alle frontiere esterne coordinando e organizzando operazioni congiunte, tenendo conto del fatto che alcune situazioni possono comportare emergenze umanitarie e il soccorso in mare, conformemente al diritto dell'Unione e al diritto internazionale;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">e)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">assiste gli Stati membri in circostanze che richiedono una maggiore assistenza tecnica e operativa alle frontiere esterne avviando interventi rapidi alle frontiere esterne degli Stati membri che fronteggiano sfide specifiche e sproporzionate, tenendo conto del fatto che alcune situazioni possono comportare emergenze umanitarie e il soccorso in mare, conformemente al diritto dell'Unione e al diritto internazionale;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">f)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">fornisce, assistenza tecnica e operativa agli Stati membri e ai paesi terzi, a norma del regolamento (UE) n. 656/2014 e del diritto internazionale, a sostegno delle operazioni di ricerca e soccorso per le persone in pericolo in mare che possono verificarsi nel corso di operazioni marittime di sorveglianza delle frontiere;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">g)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">istituisce e dispiega squadre della guardia di frontiera e costiera europea, compresa una riserva di reazione rapida, da dispiegare durante le operazioni congiunte e gli interventi rapidi alle frontiere, nonché nell'ambito di squadre di sostegno per la gestione della migrazione;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">h)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">istituisce un parco di attrezzature tecniche da impiegare nelle operazioni congiunte, negli interventi rapidi alle frontiere e nell'ambito di squadre di sostegno per la gestione della migrazione, nonché in operazioni e interventi di rimpatrio;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">i)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">nell'ambito delle squadre di sostegno per la gestione della migrazione nei punti di crisi:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">i)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">dispiega squadre della guardia di frontiera e costiera europea e attrezzatura tecnica per fornire assistenza nelle operazioni di selezione (screening), raccolta di informazioni (debriefing), identificazione e rilevamento delle impronte digitali;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">ii)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">stabilisce una procedura di orientamento e informazione iniziale in favore delle persone che necessitano di protezione internazionale o intendono presentare domanda in tal senso, in cooperazione con l'Ufficio europeo di sostegno per l'asilo (EASO) e le autorità nazionali;</p>\n</td>\n</tr>\n</tbody>\n</table>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">j)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">sostiene lo sviluppo di norme tecniche per l'attrezzatura, specialmente per il comando, il controllo e la comunicazione a livello tattico, nonché la sorveglianza tecnica per garantire l'interoperabilità a livello di Unione e nazionale;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">k)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">impiega l'attrezzatura e le guardie di frontiera necessarie e altro personale competente della riserva di reazione rapida per l'esecuzione pratica delle misure da adottare in una situazione che richieda un'azione urgente alle frontiere esterne;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">l)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">assiste gli Stati membri in circostanze che richiedono una maggiore assistenza tecnica e operativa per adempiere all'obbligo di rimpatriare i rimpatriandi, anche mediante il coordinamento o l'organizzazione di operazioni di rimpatrio;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">m)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">nell'ambito dei rispettivi mandati delle agenzie interessate, collabora con Europol ed Eurojust e assiste gli Stati membri che in circostanze che richiedono una maggiore assistenza tecnica e operativa alle frontiere esterne nella lotta alla criminalità organizzata transfrontaliera e al terrorismo;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">n)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">costituisce gruppi di osservatori e scorte per i rimpatri forzati e specialisti in materia di rimpatrio;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">o)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">costituisce e dispiega squadre europee di intervento per il rimpatrio durante gli interventi di rimpatrio;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">p)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">assiste gli Stati membri nella formazione delle guardie di frontiera nazionali, di altro personale competente e degli esperti nazionali in materia di rimpatrio, anche per quanto riguarda la definizione di standard comuni di formazione;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">q)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">partecipa allo sviluppo e alla gestione di attività di ricerca e innovazione utili per il controllo e la sorveglianza delle frontiere esterne, tra cui l'uso di tecnologie avanzate di sorveglianza ed elabora progetti pilota su materie contemplate dal presente regolamento;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">r)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">sviluppa e gestisce, in conformità del regolamento (CE) n. 45/2001 e della decisione quadro 2008/977/GAI, sistemi informativi che consentano scambi rapidi e affidabili di informazioni sui rischi emergenti nella gestione delle frontiere esterne, sull'immigrazione illegale e sul rimpatrio, in stretta collaborazione con la Commissione, gli organi, gli organismi e i servizi dell'Unione, e la rete europea sulle migrazioni istituita con decisione 2008/381/CE del Consiglio (<span class=\"oj-super oj-note-tag\">30</span>);</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">s)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">presta la necessaria assistenza per sviluppare e gestire EUROSUR e, ove opportuno, per sviluppare un ambiente comune di condivisione delle informazioni, compresa l'interoperabilità dei sistemi, in particolare istituendo, aggiornando e coordinando il quadro di EUROSUR conformemente al regolamento (UE) n. 1052/2013;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">t)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">coopera con l'Agenzia europea di controllo della pesca e l'Agenzia europea per la sicurezza marittima, nell'ambito dei rispettivi mandati, per aiutare le autorità nazionali a svolgere funzioni di guardia costiera, come stabilito all'articolo 53, fornendo servizi, informazioni, attrezzatura e formazione, nonché coordinando operazioni multifunzionali;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">u)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">assiste gli Stati membri e i paesi terzi nel contesto della cooperazione tecnica e operativa tra loro negli ambiti disciplinati dal presente regolamento;</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Gli Stati membri possono continuare a collaborare a livello operativo con altri Stati membri e/o paesi terzi qualora tale cooperazione sia compatibile con i compiti dell'Agenzia. Gli Stati membri si astengono da qualsiasi attività che possa mettere a rischio il funzionamento dell'Agenzia o il raggiungimento dei suoi obiettivi. Gli Stati membri riferiscono all'Agenzia in merito a tale cooperazione operativa con altri Stati membri e/o paesi terzi alle frontiere esterne e in materia di rimpatri. Il direttore esecutivo informa il consiglio di amministrazione in merito a tali questioni regolarmente e almeno una volta all'anno.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   L'Agenzia svolge attività di comunicazione di propria iniziativa negli ambiti che rientrano nel suo mandato. Essa fornisce al pubblico informazioni precise ed esaustive sulle sue attività.</p>\n<p class=\"oj-normal\">Le attività di comunicazione non possono pregiudicare i compiti di cui al paragrafo 1, in particolare mediante la divulgazione di informazioni operative che, se rese pubbliche, comprometterebbero il raggiungimento dell'obiettivo delle operazioni. Le attività di comunicazione sono svolte fatto salvo l'articolo 50 e in conformità dei pertinenti piani di comunicazione e divulgazione adottati dal consiglio di amministrazione.</p>\n</div>"]]}, "9": {"label": "Articolo 9", "heading": "Dovere di leale collaborazione", "anchor": "art_9", "frags": [[null, "<p class=\"oj-normal\">L'Agenzia e le autorità nazionali preposte alla gestione delle frontiere e ai rimpatri, comprese le guardie costiere nella misura in cui svolgono compiti di controllo di frontiera, hanno il dovere di collaborare lealmente e l'obbligo di scambiarsi informazioni.</p>"]]}, "10": {"label": "Articolo 10", "heading": "Obbligo di scambio di informazioni", "anchor": "art_10", "frags": [[null, "<p class=\"oj-normal\">Per svolgere i compiti conferiti loro dal presente regolamento, in particolare per monitorare i flussi migratori verso l'Unione e al suo interno, nonché per effettuare analisi del rischio e valutazioni della vulnerabilità, l'Agenzia e le autorità nazionali preposte alla gestione delle frontiere e ai rimpatri, comprese le guardie costiere, nella misura in cui svolgono compiti di controllo di frontiera, condividono, a norma del presente regolamento e di altra pertinente normativa dell'Unione e nazionale in materia di scambio di informazioni, tutte le informazioni necessarie in modo tempestivo e accurato.</p>"]]}, "11": {"label": "Articolo 11", "heading": "Monitoraggio dei flussi migratori e analisi del rischio", "anchor": "art_11", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   L'Agenzia monitora i flussi migratori diretti nell'Unione e al suo interno, le tendenze ed eventuali sfide alle frontiere esterne dell'Unione. A tale scopo, l'Agenzia, con decisione del consiglio di amministrazione su proposta del direttore esecutivo, elabora un modello comune di analisi integrata dei rischi, che è applicato dall'Agenzia stessa e dagli Stati membri. L'Agenzia effettua inoltre la valutazione delle vulnerabilità a norma dell'articolo 13.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   L'Agenzia elabora analisi del rischio, di carattere generale e le sottopone al Parlamento europeo, al Consiglio e alla Commissione a norma dell'articolo 50, nonché analisi del rischio mirato per attività operative.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   L'analisi del rischio elaborata dall'Agenzia comprende tutti gli aspetti pertinenti alla gestione europea integrata delle frontiere allo scopo di sviluppare un meccanismo di pre-allarme.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Gli Stati membri forniscono all'Agenzia tutte le informazioni necessarie sulla situazione, sulle tendenze e sulle possibili minacce alle frontiere esterne e nel settore del rimpatrio. Gli Stati membri trasmettono all'Agenzia, regolarmente o su sua richiesta, tutte le informazioni pertinenti quali dati statistici e operativi raccolti in relazione all'attuazione dell'<span class=\"oj-italic\">acquis</span> di Schengen, nonché informazioni derivanti dal livello «analisi» del quadro situazionale nazionale stabilito in conformità del regolamento (UE) n. 1052/2013.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   I risultati dell'analisi dei rischi sono presentati al consiglio di amministrazione in modo tempestivo e accurato.</p>\n</div>"], [6, "<div>\n<p class=\"oj-normal\">6.   Gli Stati membri tengono conto dei risultati dell'analisi del rischio nel pianificare le loro operazioni e attività alle frontiere esterne e le loro attività nel settore del rimpatrio.</p>\n</div>"], [7, "<div>\n<p class=\"oj-normal\">7.   L'Agenzia tiene conto dei risultati del modello comune di analisi integrata del rischio nell'elaborare un programma comune di base per la formazione delle guardie di frontiera e del personale che assolve compiti attinenti al rimpatrio.</p>\n</div>"]]}, "12": {"label": "Articolo 12", "heading": "Funzionari di collegamento negli Stati membri", "anchor": "art_12", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   L'Agenzia svolge un monitoraggio regolare della gestione delle frontiere esterne di tutti gli Stati membri tramite i suoi funzionari di collegamento.</p>\n<p class=\"oj-normal\">L'Agenzia può stabilire che un funzionario di collegamento si occupi di massimo quattro Stati membri geograficamente limitrofi.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Il direttore esecutivo nomina esperti appartenenti al personale dell'Agenzia da impiegare quali funzionari di collegamento. Sulla base dell'analisi dei rischi e in consultazione con gli Stati membri interessati, il direttore esecutivo formula una proposta sulla natura e le condizioni dell'impiego, lo Stato membro o la regione presso i quali può essere impiegato il funzionario di collegamento e gli eventuali compiti non contemplati dall'articolo 3. La proposta del direttore esecutivo è soggetta ad approvazione del consiglio di amministrazione. Il direttore esecutivo comunica la nomina allo Stato membro interessato e stabilisce, insieme allo Stato membro, la sede del distacco.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   I funzionari di collegamento agiscono a nome dell'Agenzia e hanno il ruolo di favorire la cooperazione e il dialogo tra l'Agenzia stessa e le autorità nazionali preposte alla gestione delle frontiere e ai rimpatri, comprese le guardie costiere nella misura in cui svolgono compiti di controllo di frontiera. In particolare, i funzionari di collegamento:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">fungono da interfaccia tra l'Agenzia e le autorità nazionali preposte alla gestione delle frontiere e al rimpatrio, comprese le guardie costiere nella misura in cui svolgono compiti di controllo di frontiera;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">favoriscono la raccolta di informazioni richieste dall'Agenzia ai fini del monitoraggio della migrazione illegale e delle analisi del rischio di cui all'articolo 11;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">favoriscono la raccolta di informazioni di cui all'articolo 13 e richieste dall'Agenzia per svolgere la valutazione delle vulnerabilità;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">monitorano le misure adottate dagli Stati membri alle sezioni di frontiera a cui è stato attribuito un livello alto di impatto in conformità del regolamento (UE) n. 1052/2013;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">e)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">contribuiscono a promuovere l'applicazione dell'<span class=\"oj-italic\">acquis</span> dell'Unione relativo alla gestione delle frontiere esterne, anche con riferimento al rispetto dei diritti fondamentali;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">f)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">ove possibile assistono gli Stati membri nella preparazione dei loro piani di emergenza relativi alla gestione delle frontiere;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">g)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">facilitano la comunicazione tra lo Stato membro e l'Agenzia, condividono le informazioni rilevanti in possesso dell'Agenzia con lo Stato membro, comprese le informazioni sulle operazioni in corso;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">h)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">riferiscono regolarmente al direttore esecutivo in merito alla situazione alle frontiere esterne e alla capacità dello Stato membro interessato di gestire efficacemente la situazione alle frontiere esterne; riferiscono inoltre in merito all'esecuzione delle operazioni di rimpatrio verso i pertinenti paesi terzi;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">i)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">controllano le misure adottate dallo Stato membro riguardo a una situazione che richieda un'azione urgente alle frontiere esterne di cui all'articolo 19.</p>\n</td>\n</tr>\n</tbody>\n</table>\n<p class=\"oj-normal\">Qualora nella relazione del funzionario di collegamento di cui alla lettera h) siano sollevate preoccupazioni riguardo a uno o più dei suddetti aspetti d'interesse per lo Stato membro in questione, quest'ultimo sarà informato senza indugio dal direttore esecutivo.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Ai fini del paragrafo 3, il funzionario di collegamento, in conformità con le norme nazionali e dell'Unione in materia di sicurezza e protezione dei dati:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">riceve informazioni dal centro nazionale di coordinamento e dal quadro situazionale nazionale stabilito in conformità del regolamento (UE) n. 1052/2013;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">tiene contatti regolari con le autorità nazionali preposte alla gestione delle frontiere, comprese le guardie costiere nella misura in cui svolgono compiti di controllo di frontiera, informando al contempo un punto di contatto designato dallo Stato membro interessato.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   La relazione del funzionario di collegamento fa parte della valutazione delle vulnerabilità di cui all'articolo 13. La relazione è trasmessa allo Stato membro interessato.</p>\n</div>"], [6, "<div>\n<p class=\"oj-normal\">6.   Nell'assolvere i loro compiti, i funzionari di collegamento ricevono istruzioni soltanto dall'Agenzia.</p>\n</div>"]]}, "13": {"label": "Articolo 13", "heading": "Valutazione delle vulnerabilità", "anchor": "art_13", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   L'Agenzia definisce, con decisione del consiglio di amministrazione su proposta del direttore esecutivo, una metodologia comune per la valutazione delle vulnerabilità. La metodologia comprende criteri oggettivi in base ai quali l'Agenzia effettua la valutazione delle vulnerabilità, la frequenza di tali valutazioni e le modalità con cui effettuare valutazioni consecutive delle vulnerabilità;</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   L'Agenzia monitora e valuta la disponibilità di attrezzatura tecnica, di sistemi, di capacità, di risorse, di infrastrutture e di personale degli Stati membri dotato di adeguata preparazione e competenza necessarie ai fini del controllo di frontiera. L'Agenzia effettua le predette attività come misura preventiva sulla base di un'analisi del rischio predisposta a norma dell'articolo 11, paragrafo 3. L'Agenzia effettua tale verifica e valutazione almeno una volta all'anno, a meno che il direttore esecutivo non decida altrimenti sulla scorta delle valutazioni del rischio o di una precedente valutazione della vulnerabilità.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Su richiesta dell'Agenzia, gli Stati membri forniscono informazioni circa l'attrezzatura tecnica, il personale e, nella misura del possibile, le risorse finanziarie disponibili a livello nazionale per svolgere il controllo di frontiera. Gli Stati membri forniscono informazioni sui loro piani di emergenza per la gestione delle frontiere su richiesta dell'Agenzia.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Scopo della valutazione della vulnerabilità per l'Agenzia è quello di verificare la capacità e la preparazione degli Stati membri ad affrontare prontamente possibili sfide, comprese minacce e sfide presenti e future alle frontiere esterne, identificare, specialmente per quegli Stati membri che devono fronteggiare sfide specifiche e sproporzionate, eventuali ripercussioni immediate alle frontiere esterne e conseguenze successive sul funzionamento dello spazio Schengen, e valutare la capacità di tali Stati membri di contribuire alla riserva di reazione rapida di cui all'articolo 20, paragrafo 5. Tale verifica fa salvo il meccanismo di valutazione Schengen.</p>\n<p class=\"oj-normal\">Nell'ambito di tale valutazione, l'Agenzia tiene conto della capacità degli Stati membri di espletare tutti i compiti di gestione delle frontiere, tra cui la capacità di far fronte al potenziale arrivo di un elevato numero di persone sul proprio territorio.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   I risultati della valutazione della vulnerabilità sono sottoposti agli Stati membri interessati, i quali possono formulare osservazioni su tale valutazione.</p>\n</div>"], [6, "<div>\n<p class=\"oj-normal\">6.   Ove necessario, il direttore esecutivo, in consultazione con lo Stato membro interessato, formula una raccomandazione che stabilisce le necessarie misure che lo Stato membro interessato deve adottare nonché il termine entro il quale attuare tali misure. Il direttore esecutivo invita gli Stati membri interessati ad adottare le misure necessarie.</p>\n</div>"], [7, "<div>\n<p class=\"oj-normal\">7.   Nell'elaborare le misure da raccomandare agli Stati membri interessati, il direttore esecutivo si basa sui risultati della valutazione delle vulnerabilità tenendo conto dell'analisi del rischio svolta dall'Agenzia, delle osservazioni formulate dagli Stati membri interessati e dei risultati del meccanismo di valutazione Schengen.</p>\n<p class=\"oj-normal\">Tali misure dovrebbero avere l'obiettivo di eliminare le vulnerabilità individuate nella valutazione in modo che gli Stati membri rafforzino la loro preparazione ad affrontare possibili sfide, potenziando o migliorando le loro capacità, l'attrezzatura tecnica, i sistemi, le risorse e i piani di emergenza.</p>\n</div>"], [8, "<div>\n<p class=\"oj-normal\">8.   Qualora uno Stato membro non attui le necessarie misure contenute nella raccomandazione entro il termine di cui al paragrafo 6 del presente articolo, il direttore esecutivo riferisce la questione al consiglio di amministrazione e ne informa la Commissione. Il consiglio di amministrazione adotta, su proposta del direttore esecutivo, una decisione che stabilisce le misure necessarie che lo Stato membro interessato deve adottare, nonché il termine entro il quale attuare tali misure. La decisione del consiglio di amministrazione è vincolante per lo Stato membro. Qualora uno Stato membro non attui le misure entro il termine previsto in tale decisione, il consiglio di amministrazione ne informa il Consiglio e la Commissione e ulteriori iniziative possono essere adottate in conformità dell'articolo 19.</p>\n</div>"], [9, "<div>\n<p class=\"oj-normal\">9.   A norma dell'articolo 50, l'esito della valutazione delle vulnerabilità è trasmesso periodicamente e con cadenza almeno annuale al Parlamento europeo, al Consiglio e alla Commissione.</p>\n</div>"]]}, "14": {"label": "Articolo 14", "heading": "Interventi dell'Agenzia alle frontiere esterne", "anchor": "art_14", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Uno Stato membro può chiedere all'Agenzia assistenza nell'adempimento dei propri obblighi riguardo al controllo delle frontiere esterne. L'Agenzia attua anche misure conformemente all'articolo 19.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   L'Agenzia organizza la necessaria assistenza tecnica e operativa per lo Stato membro ospitante e può adottare, in conformità del pertinente diritto dell'Unione e internazionale, compreso il principio di non respingimento, una o più delle seguenti misure:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">coordinare operazioni congiunte per uno o più Stati membri e dispiegare squadre della guardia di frontiera e costiera europea;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">organizzare interventi rapidi alle frontiere e dispiegare squadre della guardia di frontiera e costiera europea attinte dalla riserva di reazione rapida, nonché, se del caso, squadre della guardia di frontiera e costiera europea aggiuntive;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">coordinare attività per uno o più Stati membri e paesi terzi alle frontiere esterne, comprese operazioni congiunte con Stati membri vicini;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">dispiegare squadre della guardia di frontiera e costiera europea nell'ambito delle squadre di sostegno per la gestione della migrazione nei punti di crisi;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">e)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">nell'ambito delle operazioni di cui alle lettere a), b) e c) del presente paragrafo e a norma del regolamento (UE) n. 656/2014 e del diritto internazionale, fornire assistenza tecnica e operativa agli Stati membri e ai paesi terzi, a sostegno delle operazioni di ricerca e soccorso per le persone in pericolo in mare, che possono svolgersi nel corso di operazioni di sorveglianza delle frontiere in mare;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">f)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">impiegare i propri esperti e membri delle squadre che erano stati distaccati dagli Stati membri presso l'Agenzia per sostenere le autorità nazionali competenti degli Stati membri in questione per il tempo necessario;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">g)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">impiegare attrezzatura tecnica.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   L'Agenzia finanzia o cofinanzia le attività di cui al paragrafo 2 a titolo del proprio bilancio, conformemente alla normativa finanziaria applicabile all'Agenzia.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   In caso di sostanziale fabbisogno finanziario supplementare ascrivibile a una particolare situazione alle frontiere esterne, l'Agenzia ne informa tempestivamente il Parlamento europeo, il Consiglio e la Commissione.</p>\n</div>"]]}, "15": {"label": "Articolo 15", "heading": "Avvio di operazioni congiunte e interventi rapidi alle frontiere esterne", "anchor": "art_15", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Uno Stato membro può chiedere all'Agenzia di avviare operazioni congiunte per far fronte a sfide imminenti, comprese l'immigrazione illegale, minacce presenti o future alle frontiere esterne o la criminalità transfrontaliera, o di fornire loro maggiore assistenza tecnica e operativa per l'adempimento dei loro obblighi in materia di controllo delle frontiere esterne.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Su richiesta di uno Stato membro che si trovi a far fronte a sfide specifiche e sproporzionate, specie in caso di afflusso massiccio in determinati punti delle frontiere esterne di cittadini di paesi terzi che tentano di entrare nel territorio di tale Stato membro senza autorizzazione, l'Agenzia può effettuare un intervento rapido alle frontiere per un periodo limitato nel territorio di tale Stato membro ospitante.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Il direttore esecutivo valuta, approva e coordina le proposte di operazioni congiunte avanzate dagli Stati membri. Le operazioni congiunte e gli interventi rapidi alle frontiere sono preceduti da una completa, affidabile e aggiornata analisi del rischio, che consente all'Agenzia di stabilire un ordine di priorità per le operazioni congiunte e gli interventi rapidi proposti, tenendo conto del livello di impatto attribuito alle sezioni di frontiera esterna in conformità con il regolamento (UE) n. 1052/2013 e della disponibilità di risorse.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Il direttore esecutivo, sulla base dei risultati della valutazione delle vulnerabilità e tenendo conto dell'analisi del rischio svolta dall'Agenzia e del livello «analisi» del quadro situazionale europeo stabilito in conformità del regolamento (UE) n. 1052/2013, raccomanda allo Stato membro in questione di avviare e realizzare operazioni congiunte o interventi rapidi alle frontiere. L'Agenzia mette la sua attrezzatura tecnica a disposizione degli Stati membri ospitanti o partecipanti.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   Gli obiettivi di un'operazione congiunta o di un intervento rapido alle frontiere possono essere conseguiti nell'ambito di un'operazione multifunzionale. Tali operazioni possono comprendere funzioni di guardia costiera e la prevenzione della criminalità transfrontaliera, inclusa la lotta contro il traffico di migranti o la tratta di esseri umani e la gestione della migrazione, compresi l'identificazione, la registrazione, la raccolta di informazioni (<span class=\"oj-italic\">debriefing</span>) e il rimpatrio.</p>\n</div>"]]}, "16": {"label": "Articolo 16", "heading": "Piano operativo per le operazioni congiunte", "anchor": "art_16", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   In preparazione di un'operazione congiunta, il direttore esecutivo, in cooperazione con lo Stato membro ospitante, redige un elenco dell'attrezzatura tecnica e del personale necessari, tenendo conto delle risorse di cui dispone lo Stato membro ospitante. Sulla base di tali elementi, l'Agenzia definisce una serie di misure di rinforzo tecnico e operativo e di attività di sviluppo delle capacità, da includere nel piano operativo.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Il direttore esecutivo predispone un piano operativo per le operazioni congiunte alle frontiere esterne. Il direttore esecutivo e lo Stato membro ospitante, in consultazione con gli Stati membri partecipanti, concordano il piano operativo che definisce nel dettaglio gli aspetti organizzativi e procedurali dell'operazione congiunta.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Il piano operativo è vincolante per l'Agenzia, lo Stato membro ospitante e gli Stati membri partecipanti. Esso copre tutti gli aspetti considerati necessari per la realizzazione dell'operazione congiunta, fra cui i seguenti elementi:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">una descrizione della situazione con modus operandi e obiettivi dell'operazione, scopo operativo compreso;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">la durata prevedibile dell'operazione congiunta;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">l'area geografica in cui si svolgerà l'operazione congiunta;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">una descrizione dei compiti, delle responsabilità, anche per quanto riguarda il rispetto dei diritti fondamentali, e istruzioni specifiche per le squadre della guardia di frontiera e costiera europea, anche in merito all'autorizzazione a consultare banche dati e portare armi d'ordinanza, munizioni ed equipaggiamento nello Stato membro ospitante;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">e)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">la composizione delle squadre della guardia di frontiera e costiera europea e l'impiego di altro personale competente;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">f)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">disposizioni in ordine al comando e al controllo, compresi il nome e il grado delle guardie di frontiera dello Stato membro ospitante responsabili della cooperazione con i membri delle squadre e con l'Agenzia, in particolare il nome e il grado delle guardie di frontiera che hanno il comando durante l'operazione, e la posizione nella catena di comando dei membri delle squadre;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">g)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">le attrezzature tecniche da utilizzare durante l'operazione congiunta, comprensive di requisiti specifici come le condizioni d'uso, l'equipaggio richiesto, il trasporto e altri aspetti logistici, e le disposizioni finanziarie;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">h)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">disposizioni dettagliate riguardo alla comunicazione immediata di incidenti al consiglio di amministrazione e alle competenti autorità nazionali da parte dell'Agenzia;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">i)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">uno schema di relazioni e valutazioni contenente i parametri per la relazione di valutazione, anche per quanto riguarda la protezione dei diritti fondamentali, e il termine ultimo per presentare la relazione di valutazione finale;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">j)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">per le operazioni in mare, informazioni specifiche riguardanti la giurisdizione e la legislazione applicabili nell'area geografica in cui si svolge l'operazione congiunta, compresi i riferimenti al diritto nazionale, internazionale e dell'Unione in materia di intercettazione, soccorso in mare e sbarco; a tale riguardo, il piano operativo è redatto conformemente al regolamento (UE) n. 656/2014;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">k)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">le modalità di cooperazione con i paesi terzi, gli altri organi, organismi e servizi dell'Unione, o con le organizzazioni internazionali;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">l)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">procedure grazie alle quali persone che necessitano di protezione internazionale, vittime della tratta di esseri umani, minori non accompagnati e persone in situazioni vulnerabili siano indirizzate alle autorità nazionali competenti per ricevere l'assistenza adeguata;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">m)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">procedure per la creazione di un meccanismo inteso a ricevere e trasmettere all'Agenzia denunce contro tutte le persone che partecipano a un'operazione congiunta o a un intervento rapido alle frontiere, ivi compresi guardie di frontiera o altro personale competente dello Stato membro ospitante e membri delle squadre della guardia di frontiera e costiera europea, relative a presunte violazioni dei diritti fondamentali nel contesto della loro partecipazione a un'operazione congiunta o a un intervento rapido alle frontiere;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">n)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">disposizioni logistiche, comprese informazioni sulle condizioni di lavoro e sull'ambiente nelle zone in cui è prevista l'operazione congiunta.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Eventuali modifiche o adattamenti del piano operativo necessitano del consenso del direttore esecutivo e dello Stato membro ospitante, previa consultazione degli Stati membri partecipanti. L'Agenzia trasmette immediatamente copia del piano operativo modificato o adattato agli Stati membri partecipanti.</p>\n</div>"]]}, "17": {"label": "Articolo 17", "heading": "Procedura di avvio di un intervento rapido alle frontiere", "anchor": "art_17", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   La richiesta di avvio di un intervento rapido alle frontiere presentata da uno Stato membro comprende una descrizione della situazione, i possibili obiettivi e le esigenze previste. Se necessario, il direttore esecutivo può inviare immediatamente esperti dell'Agenzia per valutare la situazione alle frontiere esterne dello Stato membro interessato.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Il direttore esecutivo informa immediatamente il consiglio di amministrazione della richiesta di avvio di un intervento rapido alle frontiere presentata da uno Stato membro.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Nel decidere in merito alla richiesta presentata da uno Stato membro, il direttore esecutivo tiene conto dei risultati delle analisi dei rischi svolte dall'Agenzia e del livello «analisi» del quadro situazionale europeo definito in conformità del regolamento (UE) n. 1052/2013, nonché dei risultati della valutazione delle vulnerabilità di cui all'articolo 13 e di ogni altra informazione pertinente fornita dallo Stato membro interessato o da un altro Stato membro.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Il direttore esecutivo adotta una decisione in merito alla richiesta di avvio di un intervento rapido alle frontiere entro due giorni lavorativi dalla data di ricevimento della richiesta. Contemporaneamente il direttore esecutivo notifica per iscritto la decisione allo Stato membro interessato e al consiglio di amministrazione. Nella decisione sono precisate le motivazioni principali della stessa.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   Se decide di avviare un intervento rapido alle frontiere, il direttore esecutivo dispiega squadre della guardia di frontiera e costiera europea attinte dalla riserva di reazione rapida ai sensi dell'articolo 20, paragrafo 5, e la riserva di attrezzatura di reazione rapida ai sensi dell'articolo 39, paragrafo 7 e, se necessario, decide di fornire un rinforzo immediato mediante una o più squadre della guardia di frontiera e costiera europea, ai sensi dell'articolo 20, paragrafo 8.</p>\n</div>"], [6, "<div>\n<p class=\"oj-normal\">6.   Il direttore esecutivo, insieme allo Stato membro ospitante, predispone immediatamente, e comunque non oltre tre giorni lavorativi dalla data della decisione, un piano operativo ai sensi dell'articolo 16, paragrafo 3.</p>\n</div>"], [7, "<div>\n<p class=\"oj-normal\">7.   Non appena il piano operativo è stato concordato e trasmesso agli Stati membri, il direttore esecutivo chiede per iscritto agli Stati membri di inviare immediatamente le guardie di frontiera o altro personale competente che fanno parte della riserva di reazione rapida. Il direttore esecutivo indica i profili e il numero delle guardie di frontiera o di altro personale competente richiesti da ciascuno Stato membro tra quelli individuati nella riserva di reazione rapida.</p>\n</div>"], [8, "<div>\n<p class=\"oj-normal\">8.   Parallelamente al dispiegamento di forze di cui al paragrafo 7, e se necessario, per garantire il rinforzo immediato delle squadre della guardia di frontiera e costiera europea attinte dalla riserva di reazione rapida, il direttore esecutivo informa gli Stati membri del numero e dei profili richiesti delle guardie di frontiera o di altro personale competente da impiegare in via aggiuntiva. Tali informazioni sono fornite per iscritto ai punti di contatto nazionali, con l'indicazione della data in cui deve avere luogo l'operazione. È trasmessa agli stessi anche una copia del piano operativo.</p>\n</div>"], [9, "<div>\n<p class=\"oj-normal\">9.   Gli Stati membri provvedono affinché il numero e i profili delle guardie di frontiera o di altro personale competente assegnati alla riserva di reazione rapida siano immediatamente messi a disposizione dell'Agenzia onde garantire un dispiegamento integrale conformemente all'articolo 20, paragrafi 5 e 7. Gli Stati membri mettono inoltre a disposizione in via aggiuntiva guardie di frontiera e altro personale competente attinti dal loro contingente nazionale conformemente all'articolo 20, paragrafo 8.</p>\n</div>"], [10, "<div>\n<p class=\"oj-normal\">10.   La riserva di reazione rapida è dispiegata entro cinque giorni lavorativi dalla data di approvazione del piano operativo da parte del direttore esecutivo e dello Stato membro ospitante Il dispiegamento aggiuntivo di squadre della guardia di frontiera e costiera europea e costiere avviene se necessario, entro sette giorni lavorativi dal dispiegamento della riserva di reazione rapida</p>\n</div>"], [11, "<div>\n<p class=\"oj-normal\">11.   In caso di dispiegamento della riserva di reazione rapida, il direttore esecutivo, in consultazione con il consiglio di amministrazione, valuta immediatamente le priorità in relazione alle operazioni congiunte dell'Agenzia in corso e previste presso altre frontiere esterne, al fine di prevedere un'eventuale riallocazione delle risorse a favore di zone frontaliere esterne in cui è maggiormente necessario un dispiegamento rafforzato.</p>\n</div>"]]}, "18": {"label": "Articolo 18", "heading": "Squadre di sostegno per la gestione della migrazione", "anchor": "art_18", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Uno Stato membro che si trovi a fronteggiare sfide migratorie sproporzionate in particolari punti di crisi alle sue frontiere esterne, caratterizzate dall'arrivo di ampli flussi migratori misti, può chiedere un rinforzo tecnico e operativo da parte delle squadre di sostegno per la gestione della migrazione. Tale Stato membro presenta una richiesta di rinforzo e una valutazione delle proprie esigenze all'Agenzia e ad altre agenzie competenti dell'Unione, in particolare l'EASO ed Europol.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Il direttore esecutivo, in coordinamento con altre agenzie competenti dell'Unione, esamina la richiesta di rinforzo presentata da uno Stato membro e la valutazione delle sue esigenze allo scopo di definire un insieme completo di misure di rinforzo consistenti di varie attività coordinate dalle agenzie competenti dell'Unione, che deve essere approvato dallo Stato membro interessato.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   La Commissione, in cooperazione con lo Stato membro ospitante e le agenzie competenti, stabilisce le modalità di cooperazione presso il punto di crisi ed è responsabile del coordinamento delle attività delle squadre di sostegno per la gestione della migrazione.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Il rinforzo tecnico e operativo fornito dalle squadre della guardia di frontiera e costiera europea, dalle squadre europee di intervento per il rimpatrio e dagli esperti del personale dell'Agenzia nel contesto delle squadre di sostegno per la gestione della migrazione può comprendere:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">nel pieno rispetto dei diritti fondamentali, la fornitura di assistenza nella selezione (<span class=\"oj-italic\">screening</span>) dei cittadini di paesi terzi che arrivano alle frontiere esterne, comprese l'identificazione e la registrazione di tali cittadini e la raccolta di informazioni dai medesimi (<span class=\"oj-italic\">debriefing</span>), nonché, se richiesto dallo Stato membro, il rilevamento delle loro impronte digitali e la comunicazione di informazioni circa lo scopo di tali procedure;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">la comunicazione di informazioni preliminari alle persone che desiderano richiedere protezione internazionale e il loro indirizzamento presso le autorità nazionali competenti dello Stato membro interessato o l'EASO;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">l'assistenza tecnica e operativa nel settore del rimpatrio, compresa la preparazione e l'organizzazione di operazioni di rimpatrio.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   Le squadre di sostegno per la gestione della migrazione comprendono, ove necessario, personale specializzato in materia di protezione dei minori, tratta di esseri umani, protezione contro le persecuzioni di genere e/o diritti fondamentali.</p>\n</div>"]]}, "19": {"label": "Articolo 19", "heading": "Situazioni che richiedono un'azione urgente alle frontiere esterne", "anchor": "art_19", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Qualora il controllo delle frontiere esterne sia reso inefficace in misura tale da rischiare di compromettere il funzionamento dello spazio Schengen poiché:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">uno Stato membro non adotta le misure necessarie in conformità di una decisione del consiglio di amministrazione di cui all'articolo 13, paragrafo 8; o</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">uno Stato membro che si trova a fronteggiare sfide specifiche e sproporzionate alle frontiere esterne non ha chiesto un sostegno sufficiente all'Agenzia mediante le misure di cui all'articolo 15, 17 o 18, o non sta adottando le misure necessarie per attuare le azioni previste da tali articoli,</p>\n</td>\n</tr>\n</tbody>\n</table>\n<p class=\"oj-normal\">il Consiglio, sulla base di una proposta della Commissione, può adottare senza indugio una decisione, mediante atto di esecuzione, in cui definisce le misure che dovrebbero attenuare tali rischi e che devono essere adottate dall'Agenzia e impone allo Stato membro interessato di cooperare con l'Agenzia nell'attuazione di tali misure. La Commissione consulta l'Agenzia prima di formulare la sua proposta.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Se si verifica una situazione che richiede un'azione urgente, il Parlamento europeo ne è informato tempestivamente ed è altresì informato di tutte le ulteriori misure e decisioni adottate in risposta.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Al fine di attenuare il rischio di compromettere lo spazio Schengen, la decisione del Consiglio di cui al paragrafo 1 dispone che l'Agenzia adotti una o più delle seguenti misure:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">organizzare e coordinare interventi rapidi alle frontiere e dispiegare squadre della guardia di frontiera e costiera europea attinte dalla riserva di reazione rapida, nonché, se del caso, squadre della guardia di frontiera e costiera europea aggiuntive;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">dispiegare squadre della guardia di frontiera e costiera europea nell'ambito delle squadre di sostegno per la gestione della migrazione nei punti di crisi;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">coordinare attività per uno o più Stati membri e paesi terzi alle frontiere esterne, comprese operazioni congiunte con Stati membri vicini;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">impiegare attrezzatura tecnica;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">e)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">organizzare interventi di rimpatrio.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Il direttore esecutivo, entro due giorni lavorativi dalla data di adozione della decisione del Consiglio di cui al paragrafo 1:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">stabilisce le azioni da adottare per l'esecuzione pratica delle misure individuate in tale decisione, compresi l'attrezzatura tecnica e il numero e i profili delle guardie di frontiera e di altro personale competente necessari per conseguire gli obiettivi di tale decisione;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">redige un piano operativo e lo sottopone agli Stati membri interessati.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   Il direttore esecutivo e lo Stato membro interessato concordano il piano operativo entro tre giorni lavorativi dalla data di presentazione.</p>\n</div>"], [6, "<div>\n<p class=\"oj-normal\">6.   L'Agenzia invia tempestivamente, e comunque entro cinque giorni lavorativi dalla definizione del piano operativo, il personale necessario attinto dalla riserva di reazione rapida di cui all'articolo 20, paragrafo 5, per l'esecuzione pratica delle misure individuate nella decisione del Consiglio di cui al paragrafo 1 del presente articolo. Il dispiegamento aggiuntivo di squadre della guardia di frontiera e costiera europea avviene, se necessario, in una seconda fase e in ogni caso entro sette giorni lavorativi dal dispiegamento della riserva di reazione rapida.</p>\n</div>"], [7, "<div>\n<p class=\"oj-normal\">7.   L'Agenzia impiega tempestivamente, e comunque entro dieci giorni lavorativi dalla definizione del piano operativo, l'attrezzatura tecnica necessaria per l'esecuzione pratica delle misure individuate nella decisione del Consiglio di cui al paragrafo 1.</p>\n<p class=\"oj-normal\">L'impiego aggiuntivo di attrezzatura tecnica avviene, se necessario, in una seconda fase conformemente alle pertinenti disposizioni dell'articolo 39.</p>\n</div>"], [8, "<div>\n<p class=\"oj-normal\">8.   Lo Stato membro interessato si conforma alla decisione del Consiglio di cui al paragrafo 1. A tale scopo coopera immediatamente con l'Agenzia e intraprende le azioni necessarie per agevolare l'attuazione di tale decisione e l'esecuzione pratica delle misure stabilite nella decisione stessa e nel piano operativo concordato con il direttore esecutivo.</p>\n</div>"], [9, "<div>\n<p class=\"oj-normal\">9.   Gli Stati membri mettono a disposizione le guardie di frontiera e altro personale competente ovvero personale che assolve compiti attinenti al rimpatrio, stabiliti dal direttore esecutivo in conformità del paragrafo 4 del presente articolo. Gli Stati membri non possono invocare la situazione di cui all'articolo 20, paragrafi 3 e 8.</p>\n</div>"], [10, "<div>\n<p class=\"oj-normal\">10.   Qualora lo Stato membro interessato non si conformi alla decisione del Consiglio di cui al paragrafo 1 entro 30 giorni e non cooperi con l'Agenzia come previsto al paragrafo 8 del presente articolo, la Commissione può attivare la procedura di cui all'articolo 29 del regolamento (UE) 2016/399.</p>\n</div>"]]}, "20": {"label": "Articolo 20", "heading": "Composizione e dispiegamento delle squadre della guardia di frontiera e costiera europea", "anchor": "art_20", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   L'Agenzia impiega guardie di frontiera e altro personale competente in qualità di membri delle squadre della guardia di frontiera e costiera europea nelle operazioni congiunte, negli interventi rapidi alle frontiere e nell'ambito delle squadre di sostegno per la gestione della migrazione. L'Agenzia può inoltre impiegare esperti appartenenti al proprio personale.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Su proposta del direttore esecutivo, il consiglio di amministrazione decide a maggioranza assoluta dei membri aventi diritto di voto in merito ai profili e al numero complessivo delle guardie di frontiera e di altro personale competente da mettere a disposizione delle squadre della guardia di frontiera e costiera europea. La stessa procedura si applica per eventuali successive modifiche dei profili e del numero complessivo. Gli Stati membri contribuiscono alla formazione delle squadre della guardia di frontiera e costiera europea tramite un contingente nazionale in base ai diversi profili stabiliti, designando guardie di frontiera e altro personale competente corrispondenti ai profili richiesti.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Il contributo degli Stati membri, relativamente alle loro guardie di frontiera, a operazioni congiunte specifiche previste per l'anno successivo è programmato sulla base di negoziati e accordi bilaterali annuali tra l'Agenzia e gli Stati membri. Conformemente a tali accordi, gli Stati membri mettono a disposizione dell'Agenzia le guardie di frontiera per il loro impiego su richiesta della stessa, salvo che si trovino a far fronte a una situazione eccezionale che incide in misura sostanziale sull'adempimento dei compiti nazionali. Tale richiesta è inoltrata almeno 21 giorni lavorativi prima della missione prevista. Qualora uno Stato membro invochi una tale situazione eccezionale, esso fornisce per iscritto all'Agenzia motivazioni e informazioni dettagliate sulla situazione, il cui contenuto sarà incluso nella relazione di cui al paragrafo 12.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Per quanto riguarda gli interventi rapidi alle frontiere, su proposta del direttore esecutivo, il consiglio di amministrazione decide, a maggioranza di tre quarti, in merito ai profili e al numero minimo delle guardie di frontiera o di altro personale competente corrispondenti a tali profili da mettere a disposizione per una riserva di reazione rapida di squadre della guardia di frontiera e costiera europea. La stessa procedura si applica per eventuali successive modifiche dei profili e del numero totale delle guardie di frontiera o di altro personale competente della riserva di reazione rapida. Gli Stati membri contribuiscono alla riserva di reazione rapida tramite un contingente di esperti nazionali costituito sulla base dei diversi profili definiti, designando guardie di frontiera o altro personale competente corrispondenti ai profili richiesti.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   La riserva di reazione rapida è un corpo permanente posto a disposizione immediata dell'Agenzia, che può essere dispiegato a partire da ciascuno Stato membro entro cinque giorni lavorativi dal momento in cui il piano operativo è approvato dal direttore esecutivo e dallo Stato membro ospitante. A tale scopo, ogni Stato membro mette a disposizione dell'Agenzia ogni anno un numero di guardie di frontiera o di altro personale competente. I loro profili rispettivi corrispondono a quelli indicati nella decisione del consiglio di amministrazione. Il numero totale del personale reso disponibile dagli Stati membri ammonta come minimo a 1 500 guardie di frontiera o altro personale competente. L'Agenzia può verificare se le guardie di frontiera proposte dagli Stati membri corrispondono ai profili stabiliti. L'Agenzia può chiedere allo Stato membro di rimuovere una guardia di frontiera dalla riserva in caso di condotta scorretta o di violazione delle norme applicabili.</p>\n</div>"], [6, "<div>\n<p class=\"oj-normal\">6.   Ciascuno Stato membro è responsabile del contributo al numero di guardie di frontiera o altro personale competente stabilito al paragrafo 5, conformemente all'allegato I.</p>\n</div>"], [7, "<div>\n<p class=\"oj-normal\">7.   Gli Stati membri mettono a disposizione le guardie di frontiera e/o altro personale competente della riserva di reazione rapida per il loro impiego su richiesta dell'Agenzia. Qualora da un'analisi del rischio e, se disponibile, da una valutazione della vulnerabilità, emerga che uno Stato membro si trova a far fronte a una situazione che inciderebbe in misura sostanziale sull'adempimento dei compiti nazionali, il contributo per il dispiegamento dell'intervento rapido alle frontiere è pari alla metà del suo contributo fisso indicato nell'allegato I. Lo Stato membro ospitante in cui ha luogo un intervento rapido alle frontiere non impiega personale che fa parte del suo contributo fisso alla riserva di reazione rapida. Qualora emerga una carenza per il dispiegamento dell'intervento rapido alle frontiere, il consiglio di amministrazione decide in che modo sopperire a tale carenza, su proposta del direttore esecutivo.</p>\n</div>"], [8, "<div>\n<p class=\"oj-normal\">8.   Laddove necessario, il dispiegamento di squadre della guardia di frontiera e costiera europea attinte dalla riserva di reazione rapida è immediatamente integrato da squadre della guardia di frontiera e costiera europea aggiuntive A tale scopo, gli Stati membri, su richiesta dell'Agenzia, comunicano immediatamente il numero, i nomi e i profili delle guardie di frontiera e di altro personale competente attinti dal loro contingente nazionale che sono in grado di mettere a disposizione entro sette giorni lavorativi dall'inizio dell'intervento rapido alle frontiere. Gli Stati membri mettono a disposizione le guardie di frontiera o altro personale competente su richiesta dell'Agenzia a meno che si trovino a fronteggiare una situazione eccezionale che incide in misura sostanziale sull'adempimento dei compiti nazionali. Qualora uno Stato membro faccia valere una tale situazione eccezionale, esso fornisce per iscritto all'Agenzia motivazioni e informazioni dettagliate sulla situazione, il cui contenuto sarà incluso nella relazione di cui al paragrafo 12.</p>\n</div>"], [9, "<div>\n<p class=\"oj-normal\">9.   Se si verifica una situazione in cui si rendono necessarie più guardie di frontiera rispetto a quanto previsto ai paragrafi 5 e 8, il direttore esecutivo informa immediatamente il Parlamento europeo, il Consiglio e la Commissione. Il direttore esecutivo invita anche il Consiglio a chiedere agli Stati membri di impegnarsi per sopperire alla carenza.</p>\n</div>"], [10, "<div>\n<p class=\"oj-normal\">10.   Gli Stati membri provvedono affinché le guardie di frontiera e altro personale competente messo a disposizione siano conformi ai profili e ai numeri decisi dal consiglio di amministrazione. La durata del dispiegamento è stabilita dallo Stato membro di appartenenza ma in ogni caso non è inferiore a 30 giorni, tranne nel caso in cui l'operazione di cui fa parte il dispiegamento abbia una durata inferiore a 30 giorni.</p>\n</div>"], [11, "<div>\n<p class=\"oj-normal\">11.   L'Agenzia contribuisce alle squadre della guardia di frontiera e costiera europea con guardie di frontiera competenti o altro personale competente distaccati dagli Stati membri in qualità di esperti nazionali presso l'Agenzia. Il contributo degli Stati membri relativamente al distacco delle loro guardie di frontiera o di altro personale competente presso l'Agenzia per l'anno successivo è programmato sulla base di negoziati e accordi annuali bilaterali tra l'Agenzia e gli Stati membri. Conformemente a tali accordi, gli Stati membri mettono a disposizione le guardie di frontiera o altro personale competente per il distacco, a meno che ciò non incida in misura sostanziale sull'adempimento dei compiti nazionali. In tali situazioni, gli Stati membri possono richiamare le loro guardie di frontiera o altro personale competente distaccati.</p>\n<p class=\"oj-normal\">La durata di tali distacchi può essere di 12 mesi o più, ma in ogni caso non è inferiore a tre mesi. Le guardie di frontiera e altro personale competente distaccati sono considerati membri delle squadre e hanno gli stessi compiti e le stesse competenze dei membri delle squadre. Lo Stato membro che ha distaccato tali guardie di frontiera o altro personale competente è considerato il loro Stato membro di appartenenza.</p>\n<p class=\"oj-normal\">L'altro personale impiegato dall'Agenzia su base temporanea che non è qualificato per svolgere attività di controllo di frontiera svolge soltanto funzioni di coordinamento e altri compiti che non richiedono una formazione completa di guardia di frontiera durante le operazioni congiunte. Essi non fanno parte delle squadre della guardia di frontiera e costiera europea.</p>\n</div>"], [12, "<div>\n<p class=\"oj-normal\">12.   L'Agenzia informa ogni anno il Parlamento europeo del numero di guardie di frontiera che ciascuno Stato membro ha destinato alle squadre della guardia di frontiera e costiera europea e del numero di fatto inviato a norma del presente articolo. Tale relazione elenca gli Stati membri che hanno invocato la situazione eccezionale di cui ai paragrafi 3 e 8 nel corso dell'anno precedente. Essa include altresì le motivazioni e informazioni fornite dallo Stato membro interessato.</p>\n</div>"]]}, "21": {"label": "Articolo 21", "heading": "Istruzioni alle squadre della guardia di frontiera e costiera europea", "anchor": "art_21", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Durante il dispiegamento delle squadre della guardia di frontiera e costiera europea, lo Stato membro ospitante impartisce istruzioni alle squadre conformemente al piano operativo.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   L'Agenzia, tramite il suo funzionario di coordinamento, può comunicare allo Stato membro ospitante il suo parere sulle istruzioni impartite alle squadre della guardia di frontiera e costiera europea. In tal caso, lo Stato membro ospitante tiene conto di tale parere e lo segue nella misura del possibile.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Qualora le istruzioni impartite alle squadre della guardia di frontiera e costiera europea non siano conformi al piano operativo, l'agente di coordinamento ne informa immediatamente il direttore esecutivo, che può, se del caso, intervenire ai sensi dell'articolo 25, paragrafo 3.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Nello svolgimento dei loro compiti e nell'esercizio delle loro competenze, i membri delle squadre rispettano pienamente i diritti fondamentali, compreso l'accesso alle procedure di asilo, e la dignità umana. Qualsiasi misura che essi adottino nello svolgimento dei loro compiti e nell'esercizio delle loro competenze deve essere proporzionata agli obiettivi perseguiti dalla misura stessa. Nello svolgimento dei loro compiti e nell'esercizio delle loro competenze essi non discriminano le persone in base al sesso, alla razza o all'origine etnica, alla religione o alle convinzioni personali, alla disabilità, all'età o all'orientamento sessuale.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   I membri delle squadre restano soggetti alle misure disciplinari dei rispettivi Stati membri di appartenenza. Lo Stato membro di appartenenza predispone adeguate misure disciplinari o di altra natura conformemente al proprio diritto interno relativamente alle violazioni dei diritti fondamentali o degli obblighi in materia di protezione internazionale nel corso di un'operazione congiunta o di un intervento rapido alle frontiere.</p>\n</div>"]]}, "22": {"label": "Articolo 22", "heading": "Funzionario di coordinamento", "anchor": "art_22", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   L'Agenzia garantisce l'attuazione operativa di tutti gli aspetti organizzativi delle operazioni congiunte, dei progetti pilota e degli interventi rapidi alle frontiere, compresa la presenza di membri del suo personale.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Il direttore esecutivo nomina uno o più esperti dell'Agenzia da mettere a disposizione in qualità di funzionari di coordinamento per ogni operazione congiunta o intervento rapido alle frontiere. Il direttore esecutivo comunica la nomina allo Stato membro ospitante.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Il funzionario di coordinamento agisce a nome e per conto dell'Agenzia per tutti gli aspetti relativi al dispiegamento delle squadre della guardia di frontiera e costiera europea. Il ruolo del funzionario di coordinamento è favorire la cooperazione e il coordinamento tra gli Stati membri ospitanti e partecipanti. In particolare, l'agente di coordinamento:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">funge da interfaccia tra l'Agenzia, lo Stato membro ospitante e i membri delle squadre della guardia di frontiera e costiera europea, fornendo assistenza, per conto dell'Agenzia, su tutte le questioni connesse alle condizioni del loro impiego;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">monitora la corretta attuazione del piano operativo, anche per quanto riguarda la tutela dei diritti fondamentali, e riferisce all'Agenzia in merito;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">agisce a nome e per conto dell'Agenzia per tutti gli aspetti relativi al dispiegamento delle squadre della guardia di frontiera e costiera europea e riferisce all'Agenzia su tutti tali aspetti;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">riferisce al direttore esecutivo qualora le istruzioni impartite alle squadre della guardia di frontiera e costiera europea dallo Stato membro ospitante non siano conformi al piano operativo.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Nel contesto delle operazioni congiunte o degli interventi rapidi alle frontiere, il direttore esecutivo può autorizzare il funzionario di coordinamento a contribuire alla soluzione di eventuali disaccordi sull'esecuzione del piano operativo e sul dispiegamento delle squadre.</p>\n</div>"]]}, "23": {"label": "Articolo 23", "heading": "Punto di contatto nazionale", "anchor": "art_23", "frags": [[null, "<p class=\"oj-normal\">Gli Stati membri designano un punto di contatto nazionale per la comunicazione con l'Agenzia su tutte le questioni attinenti alle attività dell'Agenzia. Il punto di contatto nazionale è raggiungibile in qualsiasi momento.</p>"]]}, "24": {"label": "Articolo 24", "heading": "Costi", "anchor": "art_24", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   L'Agenzia copre pienamente i seguenti costi sostenuti dagli Stati membri nel mettere le loro guardie di frontiera e altro personale competente a disposizione ai fini del dispiegamento delle squadre della guardia di frontiera e costiera europea, inclusa la riserva di reazione rapida:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">spese di viaggio dallo Stato membro di appartenenza allo Stato membro ospitante e dallo Stato membro ospitante allo Stato membro di appartenenza;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">costi di vaccinazione;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">costi relativi ad assicurazioni specifiche;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">costi di assistenza sanitaria;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">e)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">diaria, spese di alloggio comprese;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">f)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">costi relativi all' attrezzatura tecnica dell'Agenzia.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Il consiglio di amministrazione stabilisce e aggiorna, ove necessario, le regole specifiche per il pagamento della diaria ai membri delle squadre della guardia di frontiera e costiera europea.</p>\n</div>"]]}, "25": {"label": "Articolo 25", "heading": "Sospensione e cessazione delle attività", "anchor": "art_25", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Il direttore esecutivo cessale attività dell'Agenzia se non ricorrono più le condizioni per lo svolgimento di tali attività. Il direttore esecutivo informa lo Stato membro interessato prima di tale cessazione.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Gli Stati membri partecipanti a un'operazione congiunta, a un intervento rapido alle frontiere o al dispiegamento delle squadre di sostegno per la gestione della migrazione possono chiedere al direttore esecutivo di cessare tale operazione congiunta, o intervento rapido alle frontiere, o impiego delle squadre di sostegno per la gestione della migrazione.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Il direttore esecutivo può revocare, dopo averne informato lo Stato membro interessato, il finanziamento di un'attività, oppure sospendere o cessare tale attività, se il piano operativo non è rispettato dallo Stato membro ospitante.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Il direttore esecutivo, dopo aver consultato il responsabile dei diritti fondamentali e informato lo Stato membro interessato, revoca il finanziamento di un'operazione congiunta, o un intervento rapido alle frontiere, un progetto pilota, il dispiegamento di squadre di sostegno per la gestione della migrazione, un'operazione di rimpatrio, un intervento o un accordo operativo di rimpatrio, oppure sospende o cessa, interamente o parzialmente, tali attività se ritiene che vi siano violazioni dei diritti fondamentali o degli obblighi in materia di protezione internazionale di natura grave o destinate a persistere. Il direttore esecutivo informa il consiglio di amministrazione di tale decisione.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   Qualora decida di sospendere o cessare il dispiegamento, da parte dell'Agenzia, di una squadra di sostegno per la gestione della migrazione, il direttore esecutivo informa di tale decisione le altre agenzie competenti che operano nell'area di tale punto di crisi.</p>\n</div>"]]}, "26": {"label": "Articolo 26", "heading": "Valutazione delle attività", "anchor": "art_26", "frags": [[null, "<p class=\"oj-normal\">Il direttore esecutivo valuta i risultati delle operazioni congiunte e degli interventi rapidi alle frontiere, dei progetti pilota, della squadra di sostegno per la gestione della migrazione e l'impiego della cooperazione operativa con i paesi terzi. Il direttore esecutivo trasmette al consiglio di amministrazione relazioni di valutazione dettagliate entro sessanta giorni dal termine di tali attività, unitamente alle osservazioni del responsabile dei diritti fondamentali. Il direttore esecutivo effettua un'analisi completa e comparativa di tali risultati allo scopo di migliorare la qualità, la coerenza e l'efficacia delle attività future e inserisce tale analisi nella relazione annuale delle attività dell'Agenzia.</p>"]]}, "27": {"label": "Articolo 27", "heading": "Rimpatrio", "anchor": "art_27", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   L'Agenzia, per quanto riguarda i rimpatri e nel rispetto dei diritti fondamentali e dei principi generali del diritto dell'Unione e del diritto internazionale, compresi gli obblighi in materia di protezione dei rifugiati e i diritti dei minori, assolve, in particolare, i seguenti compiti:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">coordina a livello tecnico e operativo le attività degli Stati membri relative ai rimpatri, comprese le partenze volontarie, al fine di instaurare un sistema integrato di gestione dei rimpatri tra le autorità competenti degli Stati membri, con la partecipazione delle autorità competenti dei paesi terzi e di altre pertinenti parti interessate;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">fornisce assistenza tecnica e operativa agli Stati membri i cui sistemi di rimpatrio sono sottoposti a sfide particolari;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">coordina l'uso di pertinenti sistemi di tecnologia dell'informazione e fornisce sostegno agli Stati membri in materia di cooperazione consolare per l'identificazione dei cittadini di paesi terzi e l'acquisizione dei documenti di viaggio, senza divulgare informazioni sul fatto che è stata presentata una domanda di protezione internazionale; organizza e coordina le operazioni di rimpatrio e fornisce sostegno alle partenze volontarie, in collaborazione con gli Stati membri;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">organizza, promuove e coordina attività che consentano lo scambio di informazioni e l'individuazione e la condivisione delle migliori prassi in materia di rimpatrio tra gli Stati membri;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">e)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">finanzia o cofinanzia le operazioni, gli interventi e le attività di cui al presente capo a titolo del proprio bilancio, conformemente alla normativa finanziaria applicabile all'Agenzia.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   L'assistenza tecnica e operativa di cui al paragrafo 1, lettera b), comprende attività intese ad aiutare gli Stati membri a espletare le procedure di rimpatrio svolte dalle autorità nazionali competenti, fornendo in particolare:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">servizi d'interpretazione;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">informazioni pratiche sui paesi terzi di rimpatrio che siano utili ai fini dell'applicazione del presente regolamento, in cooperazione, se del caso, con altri organi e organismi e servizi dell'Unione, tra cui l'EASO;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">consulenza sull'attuazione e sulla gestione delle procedure di rimpatrio in conformità della direttiva 2008/115/CE;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">consulenza e assistenza relative alle misure necessarie per garantire la disponibilità dei rimpatriandi ai fini del rimpatrio e per evitare che i rimpatriandi si rendano irreperibili, conformemente alla direttiva 2008/115/CE e al diritto internazionale.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   L'Agenzia mira a sviluppare sinergie e collegare le reti e i programmi finanziati dall'Unione in materia di rimpatrio, in stretta cooperazione con la Commissione europea e con il sostegno delle pertinenti parti interessate, compresa la rete europea sulle migrazioni.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   L'Agenzia può usufruire degli strumenti finanziari dell'Unione disponibili per attività di rimpatrio. L'Agenzia provvede affinché, nelle convenzioni di sovvenzione concluse con gli Stati membri, il sostegno finanziario sia sempre subordinato al pieno rispetto della Carta.</p>\n</div>"]]}, "28": {"label": "Articolo 28", "heading": "Operazioni di rimpatrio", "anchor": "art_28", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Senza entrare nel merito delle decisioni di rimpatrio e in conformità della direttiva 2008/115/CE, l'Agenzia fornisce l'assistenza necessaria e, su richiesta di uno o più Stati membri partecipanti, assicura il coordinamento o l'organizzazione di operazioni di rimpatrio, anche mediante il noleggio di aeromobili ai fini di tali operazioni. L'Agenzia può, di propria iniziativa, proporre agli Stati membri di coordinare o organizzare operazioni di rimpatrio.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Gli Stati membri informano l'Agenzia, con cadenza mensile, della loro previsione indicativa del numero di rimpatriandi e dei paesi terzi di rimpatrio relativamente alle pertinenti operazioni di rimpatrio su scala nazionale, e delle loro necessità di assistenza o coordinamento da parte dell'Agenzia. L'Agenzia predispone un piano operativo dinamico inteso a fornire agli Stati membri che lo richiedano il necessario rinforzo operativo, compreso in termini di attrezzatura tecnica. L'Agenzia può, di propria iniziativa o su richiesta di uno Stato membro, inserire nel piano operativo dinamico le date e le destinazioni delle operazioni di rimpatrio che ritiene necessarie, sulla base di una valutazione delle necessità. Il consiglio di amministrazione decide, su proposta del direttore esecutivo, il modus operandi del piano operativo dinamico.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   L'Agenzia può fornire l'assistenza necessaria, o su richiesta degli Stati membri partecipanti, o sulla base di una sua proposta, e assicura il coordinamento o l'organizzazione di operazioni di rimpatrio per le quali i mezzi di trasporto e le scorte per i rimpatri forzati sono messi a disposizione da un paese terzo di rimpatrio («operazioni di rimpatrio collettive»). Gli Stati membri partecipanti e l'Agenzia provvedono affinché il rispetto dei diritti fondamentali, il principio di non respingimento e l'uso proporzionato dei mezzi coercitivi siano garantiti durante l'intera operazione di rimpatrio. Almeno un rappresentante di uno Stato membro e un osservatore del rimpatrio forzato facente parte del gruppo istituito ai sensi dell'articolo 29 o del sistema nazionale di monitoraggio dello Stato membro partecipante sono presenti durante l'intera operazione di rimpatrio fino all'arrivo nel paese terzo di rimpatrio.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Il direttore esecutivo stabilisce tempestivamente un piano per le operazioni di rimpatrio collettivo. Il direttore esecutivo e lo o gli Stati membri partecipanti concordano il piano di rimpatrio che definisce nel dettaglio gli aspetti organizzativi e procedurali dell'operazione di rimpatrio collettivo, tenendo conto delle implicazioni per i diritti fondamentali e dei rischi che tali operazioni comportano. Eventuali modifiche o adattamenti di tale piano sono subordinati al consenso delle parti di cui al paragrafo 3 e al presente paragrafo.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   Il piano di rimpatrio delle operazioni di rimpatrio collettivo è vincolante per l'Agenzia e per ogni Stato membro partecipante. Esso copre tutte le misure necessarie per la realizzazione dell'operazione di rimpatrio collettivo.</p>\n</div>"], [6, "<div>\n<p class=\"oj-normal\">6.   Ciascuna operazione di rimpatrio è monitorata in conformità dell'articolo 8, paragrafo 6, della direttiva 2008/115/CE. Il monitoraggio delle operazioni di rimpatrio forzato è svolto dall'osservatore del rimpatrio forzato sulla base di criteri oggettivi e trasparenti e riguarda l'intera operazione, dalla fase precedente la partenza fino alla consegna del rimpatriando nel paese terzo di rimpatrio. L'osservatore del rimpatrio forzato presenta una relazione su ogni operazione di rimpatrio forzato al direttore esecutivo, al responsabile dei diritti fondamentali e alle autorità nazionali competenti di tutti gli Stati membri coinvolti nell'operazione. Se del caso, è assicurato un seguito adeguato da parte, rispettivamente, del direttore esecutivo e delle autorità nazionali competenti.</p>\n</div>"], [7, "<div>\n<p class=\"oj-normal\">7.   Qualora l'Agenzia nutra preoccupazioni circa il rispetto dei diritti fondamentali relativamente a un'operazione di rimpatrio, essa comunica tali preoccupazioni agli Stati membri partecipanti e alla Commissione.</p>\n</div>"], [8, "<div>\n<p class=\"oj-normal\">8.   Il direttore esecutivo valuta i risultati delle operazioni di rimpatrio. Ogni sei mesi il direttore esecutivo trasmette al consiglio di amministrazione una relazione di valutazione dettagliata su tutte le operazioni di rimpatrio effettuate nel semestre precedente, unitamente alle osservazioni del responsabile dei diritti fondamentali. Il direttore esecutivo effettua un'analisi completa e comparativa di tali risultati allo scopo di migliorare la qualità, la coerenza e l'efficacia delle future operazioni di rimpatrio. Il direttore esecutivo inserisce tale analisi nella relazione annuale delle attività dell'Agenzia.</p>\n</div>"], [9, "<div>\n<p class=\"oj-normal\">9.   L'Agenzia finanzia o cofinanzia le operazioni di rimpatrio a titolo del proprio bilancio, conformemente alle regole finanziarie applicabili all'Agenzia, dando priorità a quelle condotte da più di uno Stato membro, o a partire dai punti di crisi.</p>\n</div>"]]}, "29": {"label": "Articolo 29", "heading": "Riserva di osservatori del rimpatrio forzato", "anchor": "art_29", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   L'Agenzia, previa consultazione con il responsabile dei diritti fondamentali, costituisce una riserva di osservatori del rimpatrio forzato provenienti dagli organismi competenti, che svolgono attività di monitoraggio del rimpatrio forzato ai sensi dell'articolo 8, paragrafo 6, della direttiva 2008/115/CE e che sono stati formati conformemente all'articolo 36 del presente regolamento.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Il consiglio di amministrazione, su proposta del direttore esecutivo, determina il profilo e il numero degli osservatori del rimpatrio forzato da mettere a disposizione della riserva. La stessa procedura si applica a eventuali successive modifiche del profilo e del numero complessivo. Gli Stati membri sono responsabili del contributo alla riserva designando gli osservatori del rimpatrio forzato corrispondenti al profilo stabilito. La riserva include osservatori del rimpatrio forzato dotati di competenze specifiche in materia di protezione dei minori.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Il contributo degli Stati membri, relativamente ai loro osservatori del rimpatrio forzato, a operazioni e interventi di rimpatrio previsti per l'anno successivo è programmato sulla base di negoziati e accordi bilaterali annuali tra l'Agenzia e gli Stati membri. Conformemente a tali accordi, gli Stati membri mettono a disposizione dell'Agenzia gli osservatori del rimpatrio forzato per il loro impiego su richiesta della stessa, salvo che si trovino a far fronte a una situazione eccezionale che incide in misura sostanziale sull'adempimento dei compiti nazionali. Tale richiesta è inoltrata almeno 21 giorni lavorativi prima della missione prevista o cinque giorni lavorativi prima nel caso di un intervento rapido di rimpatrio.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   L'Agenzia mette a disposizione degli Stati membri partecipanti, su richiesta, gli osservatori del rimpatrio affinché monitorino, per loro conto, il corretto svolgimento dell'operazione di rimpatrio e degli interventi di rimpatrio per la loro intera durata. Essa mette a disposizione osservatori del rimpatrio forzato dotati di competenze specifiche in materia di protezione dei minori per qualsiasi operazione di rimpatrio che coinvolga minori.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   Gli osservatori del rimpatrio forzato restano soggetti alle misure disciplinari dei rispettivi Stati membri di appartenenza nel corso di un'operazione o di un intervento di rimpatrio.</p>\n</div>"]]}, "30": {"label": "Articolo 30", "heading": "Riserva di scorte per i rimpatri forzati", "anchor": "art_30", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   L'Agenzia costituisce una riserva di scorte per i rimpatri forzati provenienti dagli organismi nazionali competenti, che svolgono operazioni di rimpatrio in conformità dei criteri di cui all'articolo 8, paragrafi 4 e 5, della direttiva 2008/115/CE e che sono state formate conformemente all'articolo 36 del presente regolamento.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Il consiglio di amministrazione, su proposta del direttore esecutivo, determina il profilo e il numero delle scorte per i rimpatri forzati da mettere a disposizione della riserva. La stessa procedura si applica a eventuali successive modifiche del profilo e del numero complessivo. Gli Stati membri contribuiscono alla riserva designando le scorte per i rimpatri forzati corrispondenti al profilo stabilito. La riserva include scorte per i rimpatri forzati dotate di competenze specifiche in materia di protezione dei minori.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Il contributo di scorte per i rimpatri forzati da parte degli Stati membri, nelle operazioni e interventi di rimpatrio previsti per l'anno successivo è programmato sulla base di negoziati e accordi bilaterali annuali tra l'Agenzia e gli Stati membri. Conformemente a tali accordi, gli Stati membri mettono a disposizione dell'Agenzia le scorte per i rimpatri forzati per il loro impiego su richiesta della stessa, salvo che si trovino a far fronte a una situazione eccezionale che incide in misura sostanziale sull'adempimento dei compiti nazionali. Tale richiesta è inoltrata almeno 21 giorni lavorativi prima della missione prevista o cinque giorni lavorativi prima nel caso di un intervento rapido di rimpatrio.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   L'Agenzia mette a disposizione degli Stati membri partecipanti, su richiesta, tali scorte affinché scortino i rimpatriandi per loro conto e prendano parte alle operazioni e agli interventi di rimpatrio. Essa mette a disposizione scorte per i rimpatri forzati dotate di competenze specifiche in materia di protezione dei minori per qualsiasi operazione di rimpatrio che coinvolga minori.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   Le scorte per i rimpatri forzati restano soggette alle misure disciplinari dei rispettivi Stati membri di appartenenza nel corso di un'operazione o di un intervento di rimpatrio.</p>\n</div>"]]}, "31": {"label": "Articolo 31", "heading": "Riserva di esperti in materia di rimpatrio", "anchor": "art_31", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   L'Agenzia istituisce una riserva di esperti in materia di rimpatrio provenienti dagli organismi nazionali competenti e dal personale dell'Agenzia, che abbiano le capacità e le competenze necessarie per lo svolgimento delle attività relative al rimpatrio e che siano stati formati conformemente all'articolo 36. Tali esperti sono messi a disposizione per svolgere compiti specifici, quali l'identificazione di particolari gruppi di cittadini di paesi terzi, l'acquisizione dei documenti di viaggio dai paesi terzi e la facilitazione della cooperazione consolare.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Il consiglio di amministrazione, su proposta del direttore esecutivo, determina il profilo e il numero degli esperti in materia di rimpatrio da mettere a disposizione della riserva. La stessa procedura si applica a eventuali successive modifiche del profilo e del numero complessivo. Gli Stati membri contribuiscono alla riserva designando gli esperti corrispondenti al profilo stabilito. La riserva include esperti in materia di rimpatrio dotati di competenze specifiche in materia di protezione dei minori.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Il contributo degli Stati membri, relativamente ai loro esperti in materia di rimpatrio, a operazioni e interventi di rimpatrio previsti per l'anno successivo è programmato sulla base di negoziati e accordi bilaterali annuali tra l'Agenzia e gli Stati membri. Conformemente a tali accordi, gli Stati membri mettono a disposizione dell'Agenzia gli esperti in materia di rimpatrio per il loro impiego su richiesta della stessa, salvo che si trovino a far fronte a una situazione eccezionale che incide in misura sostanziale sull'adempimento dei compiti nazionali. Tale richiesta è inoltrata almeno 21 giorni lavorativi prima della missione prevista o cinque giorni lavorativi prima nel caso di un intervento rapido di rimpatrio.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   L'Agenzia mette a disposizione degli Stati membri partecipanti, su richiesta, gli esperti in materia di rimpatrio durante le operazioni di rimpatrio e affinché prendano parte a interventi di rimpatrio. Essa mette a disposizione esperti in materia di rimpatrio dotati di competenze specifiche in materia di protezione dei minori per qualsiasi operazione di rimpatrio che coinvolga minori.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   Gli esperti in materia di rimpatrio restano soggetti alle misure disciplinari dei rispettivi Stati membri di appartenenza nel corso di un'operazione o di un intervento di rimpatrio.</p>\n</div>"]]}, "32": {"label": "Articolo 32", "heading": "Squadre europee di intervento per i rimpatri", "anchor": "art_32", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   L'Agenzia istituisce, a partire dalle riserve di cui agli articoli 29, 30 e 31, squadre europee ad hoc di intervento per i rimpatri che saranno utilizzate durante gli interventi di rimpatrio.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Gli articoli 21, 22 e 24 si applicano, <span class=\"oj-italic\">mutatis mutandis</span>, alle squadre europee di intervento per i rimpatri.</p>\n</div>"]]}, "33": {"label": "Articolo 33", "heading": "Interventi di rimpatrio", "anchor": "art_33", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Nei casi in cui uno Stati membro debba affrontare oneri nell'attuazione dell'obbligo di rimpatrio di cittadini di paesi terzi soggetti a una decisione di rimpatrio emessa da uno Stato membro, l'Agenzia fornisce, su richiesta di tale Stato membro, l'adeguata assistenza tecnica e operativa sotto forma di intervento di rimpatrio. Tale intervento può consistere nel dispiegamento di squadre europee di intervento per i rimpatri nello Stato membro ospitante e nell'organizzazione di operazioni di rimpatrio dallo Stato membro ospitante.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Nei casi in cui uno Stato membro sia soggetto a una sfida specifica e sproporzionata nell'attuazione del suo obbligo di rimpatrio di cittadini di paesi terzi soggetti a una decisione di rimpatrio emessa da uno Stato membro, l'Agenzia fornisce, su richiesta di tale Stato membro, l'adeguata assistenza tecnica e operativa sotto forma di intervento di rimpatrio o di intervento rapido di rimpatrio. L'Agenzia può proporre di propria iniziativa di fornire allo Stato membro tale assistenza tecnica e operativa. Un intervento rapido di rimpatrio può consistere nel dispiegamento tempestivo di squadre europee di intervento per i rimpatri nello Stato membro ospitante e nell'organizzazione di operazioni di rimpatrio dallo Stato membro ospitante.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Nel contesto di un intervento di rimpatrio il direttore esecutivo stabilisce tempestivamente un piano operativo, di concerto con lo Stato membro ospitante e con gli Stati membri partecipanti. Si applicano le pertinenti disposizioni dell'articolo 16.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Il direttore esecutivo adotta una decisione in merito al piano operativo quanto prima e, nel caso di cui al paragrafo 2, entro cinque giorni lavorativi. La decisione è immediatamente notificata per iscritto agli Stati membri interessati e al Consiglio di amministrazione.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   L'Agenzia finanzia o cofinanzia gli interventi di rimpatrio dal proprio bilancio, conformemente alle regole finanziarie applicabili all'Agenzia.</p>\n</div>"]]}, "34": {"label": "Articolo 34", "heading": "Protezione dei diritti fondamentali e strategia in materia di diritti fondamentali", "anchor": "art_34", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   La guardia di frontiera e costiera europea garantisce la tutela dei diritti fondamentali nell'esecuzione dei suoi compiti a norma del presente regolamento in conformità del pertinente diritto dell'Unione, in particolare la Carta, il diritto internazionale pertinente, compresi la convenzione del 1951 relativa allo status di rifugiati e il suo protocollo del 1967, così come degli obblighi inerenti all'accesso alla protezione internazionale, in particolare il principio di non respingimento.</p>\n<p class=\"oj-normal\">A tal fine, l'Agenzia elabora, sviluppa ulteriormente e attua una strategia in materia di diritti fondamentali, che preveda un meccanismo efficace per monitorare il rispetto dei diritti fondamentali in tutte le proprie attività.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Nell'esecuzione dei suoi compiti, la guardia di frontiera e costiera europea provvede affinché nessuno sia sbarcato, obbligato a entrare o condotto in un paese, o altrimenti consegnato o riconsegnato alle autorità dello stesso, in violazione del principio di non respingimento, o in un paese nel quale sussista un rischio di espulsione o di rimpatrio verso un altro paese in violazione di detto principio.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Nell'esecuzione dei suoi compiti, la guardia di frontiera e costiera europea tiene conto delle particolari esigenze dei minori, dei minori non accompagnati, delle persone con disabilità, delle vittime della tratta di esseri umani, delle persone bisognose di assistenza medica, delle persone bisognose di protezione internazionale, delle persone in pericolo in mare e di chiunque si trovi in una situazione di particolare vulnerabilità.</p>\n<p class=\"oj-normal\">La guardia e di frontiera e costiera europea presta particolare attenzione ai diritti dei minori in modo da garantire che in tutte le sue attività sia rispettato il loro interesse superiore.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Nell'esecuzione dei suoi compiti, nelle sue relazioni con gli Stati membri e nel quadro della cooperazione con i paesi terzi, l'Agenzia tiene conto delle relazioni redatte dal forum consultivo di cui all'articolo 70 («foro consultivo») e dal responsabile dei diritti fondamentali.</p>\n</div>"]]}, "35": {"label": "Articolo 35", "heading": "Codici di condotta", "anchor": "art_35", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   L'Agenzia, in cooperazione con il forum consultivo, elabora e sviluppa ulteriormente un codice di condotta applicabile a tutte le operazioni di controllo di frontiera coordinate dall'agenzia e da tutti coloro che prendono parte alle attività dell'Agenzia. Il codice di condotta stabilisce procedure intese a garantire i principi dello Stato di diritto e il rispetto dei diritti fondamentali, con particolare attenzione nel caso delle persone vulnerabili, compresi i minori, i minori non accompagnati e altre persone vulnerabili, come anche delle persone che chiedono protezione internazionale.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   L'Agenzia, in cooperazione con il forum consultivo, elabora e aggiorna periodicamente un codice di condotta per il rimpatrio dei rimpatriandi, che si applica durante tutte le operazioni di rimpatrio e gli interventi di rimpatrio coordinati o organizzati dall'Agenzia. Tale codice di condotta descrive procedure standard comuni dirette a semplificare l'organizzazione delle operazioni e degli interventi di rimpatrio e a garantire che esse si svolgano in maniera umana e nel pieno rispetto dei diritti fondamentali, segnatamente la dignità umana, la proibizione della tortura e delle pene o trattamenti inumani o degradanti, il diritto alla libertà e alla sicurezza e il diritto alla protezione dei dati personali e la non discriminazione.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Il codice di condotta per i rimpatri terrà conto in particolare dell'obbligo degli Stati membri di prevedere un sistema di monitoraggio efficace dei rimpatri forzati di cui all'articolo 8, paragrafo 6, della direttiva 2008/115/CE, e della strategia in materia di diritti fondamentali.</p>\n</div>"]]}, "36": {"label": "Articolo 36", "heading": "Formazione", "anchor": "art_36", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   L'Agenzia, in collaborazione con i competenti organismi di formazione degli Stati membri e, se del caso, dell'EASO e dell'Agenzia dell'Unione europea per i diritti fondamentali, sviluppa specifici strumenti formativi, incluse formazioni specifiche in materia di protezione dei minori e di altre persone vulnerabili, e fornisce alle guardie di frontiera e ad altri membri competenti del personale che fanno parte delle squadre della guardia di frontiera e costiera europea formazioni avanzate in relazione ai loro compiti e alle loro competenze. Esperti facenti parte dell'organico dell'Agenzia svolgono esercitazioni periodiche con dette guardie di frontiera secondo il calendario della formazione avanzata e delle esercitazioni stabilito nel programma di lavoro annuale dell'Agenzia.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   L'Agenzia adotta le iniziative necessarie per assicurare che tutte le guardie di frontiera e gli altri membri del personale degli Stati membri che fanno parte delle squadre della guardia di frontiera e costiera europea, come anche il personale dell'Agenzia, abbiano ricevuto, una formazione sul pertinente diritto dell'Unione e internazionale, compresi i diritti fondamentali, l'accesso alla protezione internazionale e, se del caso, la ricerca e il soccorso, prima di partecipare alle attività operative organizzate dall'Agenzia.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   L'Agenzia finanzia al 100 % la formazione delle guardie di frontiera che compongono la riserva di reazione rapida di cui all'articolo 20, paragrafo 5, ai fini della loro partecipazione alla riserva.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   L'Agenzia adotta le iniziative necessarie al fine di assicurare la formazione del personale coinvolto in compiti attinenti ai rimpatri che farà parte delle riserve di cui agli articoli 29, 30 e 31. L'Agenzia assicura che il proprio personale e tutti i membri del personale che partecipano alle operazioni di rimpatrio e agli interventi di rimpatrio, abbiano ricevuto una formazione sul pertinente diritto dell'Unione e internazionale, compresi i diritti fondamentali e l'accesso alla protezione internazionale, prima di partecipare alle attività operative organizzate dall'Agenzia.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   L'Agenzia crea e sviluppa un programma comune di base per la formazione delle guardie di frontiera e offre formazione a livello europeo per gli istruttori delle guardie di frontiera nazionali degli Stati membri, anche in materia di diritti fondamentali, di accesso alla protezione internazionale e per quanto riguarda il pertinente diritto del mare. Il programma comune di base mira a promuovere gli standard più elevati e le migliori prassi nell'attuazione della normativa dell'Unione in materia di gestione delle frontiere. L'Agenzia redige il programma comune di base previa consultazione del forum consultivo e del responsabile dei diritti fondamentali. Gli Stati membri integrano tale programma comune di base nei corsi di formazione organizzati per le rispettive guardie di frontiera nazionali e il personale che partecipa a compiti attinenti ai rimpatri.</p>\n</div>"], [6, "<div>\n<p class=\"oj-normal\">6.   L'Agenzia offre inoltre al personale dei servizi nazionali competenti degli Stati membri e, se del caso, di paesi terzi, corsi e seminari di formazione supplementari su temi riguardanti il controllo delle frontiere esterne e il rimpatrio dei cittadini di paesi terzi.</p>\n</div>"], [7, "<div>\n<p class=\"oj-normal\">7.   L'Agenzia può organizzare attività di formazione in cooperazione con gli Stati membri e i paesi terzi nel loro territorio.</p>\n</div>"], [8, "<div>\n<p class=\"oj-normal\">8.   L'Agenzia istituisce un programma di scambi inteso a consentire alle guardie di frontiera che partecipano alle squadre della guardia di frontiera e costiera europea e al personale che prende parte alle squadre di intervento per i rimpatri di acquisire conoscenze o competenze specifiche grazie alle esperienze e alle buone prassi applicate all'estero, lavorando con le guardie di frontiera e il personale coinvolto in compiti attinenti ai rimpatri in uno Stato membro diverso dal proprio.</p>\n</div>"]]}, "37": {"label": "Articolo 37", "heading": "Ricerca e innovazione", "anchor": "art_37", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   L'Agenzia provvede proattivamente a monitorare le attività di ricerca e di innovazione pertinenti per la gestione europea integrata delle frontiere, compreso l'impiego di avanzate tecnologie di sorveglianza. L'Agenzia provvede a divulgare i risultati di tali ricerche al Parlamento europeo, agli Stati membri e alla Commissione conformemente all'articolo 50. Tali risultati possono essere utilizzati nel modo opportuno in operazioni congiunte, interventi rapidi alle frontiere, operazioni di rimpatrio e interventi di rimpatrio.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   L'Agenzia assiste gli Stati membri e la Commissione nell'identificazione dei principali temi di ricerca. L'Agenzia assiste gli Stati membri e la Commissione nell'elaborazione e nell'attuazione dei pertinenti programmi quadro dell'Unione per le attività di ricerca e innovazione.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   L'Agenzia attua le parti del programma quadro per la ricerca e l'innovazione che riguardano la sicurezza delle frontiere. A tal fine, e qualora la Commissione le abbia delegato i pertinenti poteri, l'Agenzia svolge i seguenti compiti:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">la gestione di alcune fasi di esecuzione del programma e di alcune fasi della vita di progetti specifici sulla base dei pertinenti programmi di lavoro adottati dalla Commissione;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">l'adozione degli atti di esecuzione del bilancio delle entrate e delle spese e l'esecuzione di tutte le operazioni necessarie alla gestione del programma;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">la fornitura di sostegno all'attuazione dei programmi.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   L'Agenzia può pianificare e attuare progetti pilota concernenti le materie oggetto del presente regolamento.</p>\n</div>"]]}, "38": {"label": "Articolo 38", "heading": "Acquisto o noleggio di attrezzatura tecnica", "anchor": "art_38", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   L'Agenzia può acquistare, autonomamente o in comproprietà con uno Stato membro, o noleggiare attrezzatura tecnica da mettere a disposizione durante operazioni congiunte, progetti pilota, interventi rapidi alle frontiere, operazioni di rimpatrio, interventi di rimpatrio, il dispiegamento di squadre di sostegno per la gestione della migrazione o progetti di assistenza tecnica, conformemente alle regole finanziarie applicabili all'Agenzia.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   L'Agenzia può acquistare attrezzature tecniche su decisione del direttore esecutivo in consultazione con il consiglio di amministrazione. L'acquisto o il noleggio di attrezzature comportanti costi ingenti a carico dell'Agenzia sono preceduti da un'attenta analisi costi-benefici e del fabbisogno. Tali eventuali spese sono iscritte nel bilancio dell'Agenzia adottato dal consiglio di amministrazione.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Ove l'Agenzia acquisti o noleggi attrezzature tecniche di grande rilievo, si applicano le seguenti condizioni:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">in caso di acquisto da parte dell'Agenzia o di comproprietà, l'Agenzia concorda con uno Stato membro che esso provveda all'immatricolazione dell'attrezzatura conformemente alla legislazione applicabile di tale Stato membro;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">in caso di noleggio, l'attrezzatura è immatricolata in uno Stato membro.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Sulla base di un modello di accordo redatto dall'Agenzia e approvato dal consiglio di amministrazione, lo Stato membro di immatricolazione e l'Agenzia stabiliscono di comune accordo le modalità che garantiscono l'interoperabilità dell'attrezzatura e le condizioni d'uso dell'attrezzatura, comprese le disposizioni specifiche sul dispiegamento rapido durante gli interventi rapidi alle frontiere. In caso di risorse in comproprietà, le modalità includono anche i periodi di piena disponibilità delle risorse per l'Agenzia. L'attrezzatura tecnica di proprietà esclusiva dell'Agenzia è messa a disposizione dell'Agenzia su richiesta della stessa, e lo Stato membro di registrazione non può invocare la situazione eccezionale di cui all'articolo 39, paragrafo 8.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   Lo Stato membro di immatricolazione o il fornitore dell'attrezzatura tecnica mettono a disposizione gli esperti e il personale tecnico necessari per un uso dell'attrezzatura tecnica nel rispetto delle norme e in sicurezza.</p>\n</div>"]]}, "39": {"label": "Articolo 39", "heading": "Parco attrezzature tecniche", "anchor": "art_39", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   L'Agenzia crea e conserva registri centralizzati del parco attrezzature tecniche comprendente l'attrezzatura di proprietà degli Stati membri o dell'Agenzia e l'attrezzatura in comproprietà degli Stati membri e dell'Agenzia utilizzate per le sue attività operative.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   L'attrezzatura di proprietà esclusiva dell'Agenzia è pienamente disponibile e pronta per essere utilizzata in qualunque momento, come previsto all'articolo 38, paragrafo 4.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   L'attrezzatura in comproprietà dell'Agenzia, detenuta per una quota superiore al 50 %, è anch'essa disponibile per essere impiegata conformemente a un accordo stipulato tra uno Stato membro e l'Agenzia, come previsto all'articolo 38, paragrafo 4.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   L'Agenzia assicura la compatibilità e l'interoperabilità dell'attrezzatura elencata nel parco attrezzature tecniche.</p>\n<p class=\"oj-normal\">A tal fine definisce le norme tecniche che deve soddisfare l'attrezzatura per essere utilizzata nelle attività dell'Agenzia, se necessario. L'attrezzatura che l'Agenzia deve acquisire, in proprietà esclusiva o in comproprietà, e l'attrezzatura di proprietà degli Stati membri elencata nel parco attrezzature tecniche deve rispettare tali norme tecniche.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   Il direttore esecutivo individua il numero minimo di attrezzature tecniche richiesti in vista del fabbisogno dell'Agenzia, in particolare per quanto riguarda l'esecuzione di operazioni congiunte, il dispiegamento di squadre di sostegno per la gestione della migrazione, gli interventi rapidi alle frontiere, le operazioni di rimpatrio e gli interventi di rimpatrio, conformemente al suo programma di lavoro per l'anno in questione.</p>\n<p class=\"oj-normal\">Se il numero minimo di attrezzature tecniche dovesse rivelarsi insufficiente per eseguire il piano operativo concordato per le tali operazioni, l'Agenzia lo rivede in funzione di esigenze giustificate e di un accordo con gli Stati membri.</p>\n</div>"], [6, "<div>\n<p class=\"oj-normal\">6.   Il parco attrezzature tecniche è composto da un numero minimo di attrezzature identificate come necessarie all'Agenzia per tipo di attrezzatura tecnica. Le unità rientranti nel parco attrezzature tecniche sono utilizzate nel quadro di operazioni congiunte, il dispiegamento di squadre di sostegno per la gestione della migrazione, progetti pilota, interventi rapidi alle frontiere, operazioni di rimpatrio o interventi di rimpatrio.</p>\n</div>"], [7, "<div>\n<p class=\"oj-normal\">7.   Il parco attrezzature tecniche comprende una riserva di attrezzatura di reazione rapida che contiene un numero limitato di attrezzature necessarie per eventuali interventi rapidi alle frontiere. I contributi degli Stati membri alla riserva di attrezzatura di reazione rapida sono programmati conformemente ai negoziati e agli accordi annuali bilaterali di cui al paragrafo 8. Relativamente all'attrezzatura indicata nell'elenco delle attrezzature di tale riserva, gli Stati membri non possono invocare la situazione eccezionale di cui al paragrafo 8.</p>\n<p class=\"oj-normal\">Le attrezzature indicate in tale elenco sono inviate a destinazione ai fini dell'impiego, quanto prima possibile, e comunque entro 10 giorni dalla data in cui viene stabilito di comune accordo il piano operativo.</p>\n<p class=\"oj-normal\">L'Agenzia contribuisce a tale riserva con l'attrezzatura a sua disposizione ai sensi di quanto stabilito all'articolo 38, paragrafo 1.</p>\n</div>"], [8, "<div>\n<p class=\"oj-normal\">8.   Gli Stati membri contribuiscono al parco attrezzature tecniche. Il loro apporto al parco attrezzature tecniche e l'utilizzo di questa per operazioni specifiche sono programmati sulla base di negoziati e accordi annuali bilaterali tra l'Agenzia e gli Stati membri. Conformemente a tali accordi e nella misura in cui l'attrezzatura rientra nel numero minimo di attrezzature tecniche fornite per un anno determinato, gli Stati membri mettono a disposizione l'attrezzatura tecnica su richiesta dell'Agenzia, a meno che si trovino a far fronte a una situazione eccezionale che incide in misura sostanziale sull'adempimento dei compiti nazionali. Qualora uno Stato membro invochi una tale situazione eccezionale, esso fornisce per iscritto all'Agenzia motivazioni e informazioni dettagliate sulla situazione, il cui contenuto sarà incluso nella relazione di cui al paragrafo 13. La richiesta dell'Agenzia è inoltrata almeno 45 giorni prima dell'utilizzo previsto per l'attrezzatura tecnica di grande rilievo e 30 giorni prima dell'utilizzo previsto per l'altra attrezzatura. L'apporto al parco attrezzatura tecnica è soggetto a revisione annua.</p>\n</div>"], [9, "<div>\n<p class=\"oj-normal\">9.   Su proposta del direttore esecutivo, il consiglio di amministrazione decide su base annua le regole relative all'attrezzatura tecnica, in particolare il numero minimo complessivo per tipo di attrezzatura tecnica e le modalità di impiego e di rimborso dei costi e al numero limitato di attrezzature tecniche per la riserva di attrezzatura di reazione rapida. Per motivi di bilancio, la decisione è adottata dal consiglio di amministrazione entro il 30 giugno di ogni anno.</p>\n</div>"], [10, "<div>\n<p class=\"oj-normal\">10.   Se ha luogo un'operazione di intervento rapido alle frontiere, l'articolo 17, paragrafo 11, si applica di conseguenza.</p>\n</div>"], [11, "<div>\n<p class=\"oj-normal\">11.   Ove necessità impreviste di attrezzatura tecnica per un'operazione congiunta o un intervento rapido alle frontiere emerga dopo la fissazione del numero minimo di attrezzature tecniche, e tali necessità non possano essere soddisfatte ricorrendo al parco attrezzature tecniche o alla riserva di attrezzatura di reazione rapida, gli Stati membri, laddove possibile, mettono a disposizione dell'Agenzia, su richiesta di quest'ultima e su una base ad hoc, l'attrezzatura tecnica necessaria disponibile per l'impiego.</p>\n</div>"], [12, "<div>\n<p class=\"oj-normal\">12.   Il direttore esecutivo riferisce periodicamente al consiglio di amministrazione circa la composizione e l'impiego dell'attrezzatura che fa parte del parco attrezzatura tecnica. Ove non sia raggiunto il numero minimo di attrezzature tecniche richieste nel parco, il direttore esecutivo ne informa immediatamente il consiglio di amministrazione. Il consiglio di amministrazione decide senza indugio l'ordine di priorità nell'utilizzo dell'attrezzatura tecnica e adotta opportune misure per correggere le carenze. Il consiglio di amministrazione comunica alla Commissione le carenze e le misure che ha adottato. La Commissione ne informa successivamente il Parlamento europeo e il Consiglio, esprimendo altresì la propria valutazione.</p>\n</div>"], [13, "<div>\n<p class=\"oj-normal\">13.   L'Agenzia presenta annualmente al Parlamento europeo una relazione sul numero di attrezzature tecniche che ciascuno Stato membro si è impegnato a mettere a disposizione del parco attrezzatura tecnica a norma del presente articolo. Tale relazione elenca gli Stati membri che hanno invocato la situazione eccezionale di cui al paragrafo 8 nel corso dell'anno precedente e include le motivazioni e le informazioni fornite dallo Stato membro interessato.</p>\n</div>"], [14, "<div>\n<p class=\"oj-normal\">14.   Gli Stati membri registrano nel parco attrezzatura tecnica tutti i mezzi di trasporto e l'attrezzatura operativa acquistati nell'ambito delle azioni specifiche del Fondo sicurezza interna, in conformità dell'articolo 7, paragrafo 1, del regolamento (UE) n. 515/2014 del Parlamento europeo e del Consiglio (<span class=\"oj-super oj-note-tag\">31</span>) o, se del caso, nell'ambito di qualsiasi altro finanziamento specifico dell'Unione messo a disposizione degli Stati membri al fine di incrementare la capacità operativa dell'Agenzia. Tale attrezzatura tecnica rientra nel numero minimo di attrezzature tecniche fornite per un determinato anno.</p>\n<p class=\"oj-normal\">Gli Stati membri rendono tale attrezzatura tecnica disponibile per l'impiego all'Agenzia su richiesta della stessa. Nel caso di un'operazione di cui all'articolo 17 o all'articolo 19 del presente regolamento, essi non possono far valere la situazione eccezionale di cui al paragrafo 8 del presente articolo.</p>\n</div>"], [15, "<div>\n<p class=\"oj-normal\">15.   L'Agenzia gestisce il registro del parco attrezzatura tecnica come segue:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">classificazione per tipo di attrezzatura e per tipo di operazione;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">classificazione per proprietario (Stato membro, agenzia, altro);</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">numero complessivo delle attrezzature necessarie;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">requisiti relativi all'equipaggio, se applicabile;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">e)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">altre informazioni quali dati di immatricolazione, condizioni di trasporto e manutenzione, regimi nazionali di esportazione applicabili, istruzioni tecniche, ovvero altre informazioni necessarie per un uso appropriato dell'attrezzatura.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [16, "<div>\n<p class=\"oj-normal\">16.   L'Agenzia finanzia al 100 % l'utilizzo dell'attrezzatura tecnica rientrante nel numero minimo di attrezzature tecniche fornite da un determinato Stato membro per un anno determinato. L'impiego di attrezzatura tecnica che non rientra in tale numero minimo è cofinanziato dall'Agenzia fino a un massimo del 100 % delle spese ammissibili, tenendo conto delle particolari circostanze degli Stati membri che inviano detta attrezzatura tecnica.</p>\n</div>"]]}, "40": {"label": "Articolo 40", "heading": "Compiti e competenze dei membri delle squadre", "anchor": "art_40", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   I membri delle squadre devono possedere le capacità per svolgere tutti i compiti ed esercitare tutte le competenze relativi ai controlli di frontiera e ai rimpatri, nonché quelle necessarie per conseguire gli obiettivi del regolamento (UE) 2016/399 e della direttiva 2008/115/CE.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Nello svolgimento dei loro compiti e nell'esercizio delle loro competenze, i membri delle squadre osservano il diritto dell'Unione e quello internazionale e rispettano i diritti fondamentali e la legislazione nazionale dello Stato membro ospitante.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   I membri delle squadre possono svolgere compiti ed esercitare competenze esclusivamente sotto il controllo e, di norma, in presenza di guardie di frontiera o di personale coinvolto nei compiti attinenti al rimpatrio dello Stato membro ospitante. Lo Stato membro ospitante può autorizzare i membri delle squadre ad agire per suo conto.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   I membri delle squadre indossano, se del caso, le proprie uniformi nello svolgimento dei loro compiti e nell'esercizio delle loro competenze. Sull'uniforme portano inoltre un'identificazione personale visibile e un bracciale blu con il distintivo dell'Unione europea e dell'Agenzia, che li identifica come partecipanti a un'operazione congiunta, in un intervento di una squadra di sostegno per la gestione della migrazione, in un progetto pilota, in un intervento rapido alle frontiere, in un'operazione di rimpatrio o in un intervento di rimpatrio. Perché siano identificabili dalle autorità nazionali dello Stato membro ospitante, i membri delle squadre sono sempre muniti di un documento di riconoscimento, che esibiscono su richiesta.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   Nello svolgimento dei loro compiti e nell'esercizio delle loro competenze, i membri delle squadre possono portare le armi di ordinanza, le munizioni e l'equipaggiamento autorizzati in conformità della legislazione nazionale dello Stato membro di origine. Tuttavia, lo Stato membro ospitante può vietare il porto di determinate armi di ordinanza, munizioni ed equipaggiamento, a condizione che la sua legislazione applichi il medesimo divieto alle proprie guardie di frontiera o al personale impegnato in compiti attinenti ai rimpatri. Prima dell'impiego dei membri delle squadre, lo Stato membro ospitante informa l'Agenzia in merito alle armi di ordinanza, alle munizioni e all'equipaggiamento autorizzati e alle relative condizioni d'uso. L'Agenzia mette tali informazioni a disposizione degli Stati membri.</p>\n</div>"], [6, "<div>\n<p class=\"oj-normal\">6.   Nello svolgimento dei loro compiti e nell'esercizio delle loro competenze, i membri delle squadre sono autorizzati a ricorrere all'uso della forza, incluso l'uso delle armi di ordinanza, delle munizioni e dell'equipaggiamento, soltanto con il consenso dello Stato membro di appartenenza e dallo Stato membro ospitante, alla presenza delle guardie di frontiera dello Stato membro ospitante e conformemente alla sua legislazione nazionale. Lo Stato membro ospitante può, con il consenso dello Stato membro di appartenenza, autorizzare i membri delle squadre a usare la forza in assenza di guardie di frontiera dello Stato membro ospitante.</p>\n</div>"], [7, "<div>\n<p class=\"oj-normal\">7.   Le armi di ordinanza, le munizioni e l'equipaggiamento possono essere usati per legittima difesa personale o per legittima difesa dei membri della squadra o di altre persone conformemente alla legislazione nazionale dello Stato membro ospitante.</p>\n</div>"], [8, "<div>\n<p class=\"oj-normal\">8.   Ai fini del presente regolamento, lo Stato membro ospitante autorizza i membri delle squadre a consultare le banche dati europee se tale consultazione è necessaria a conseguire gli obiettivi operativi specificati nel piano operativo per i controlli di frontiera, la sorveglianza di frontiera e i rimpatri. Lo Stato membro ospitante li può anche autorizzare a consultare le proprie banche dati nazionali, se necessario, per i medesimi obbiettivi. Gli Stati membri provvedono a fornire l'accesso alle banche dati in modo efficiente ed efficace. I membri delle squadre consultano soltanto i dati necessari per lo svolgimento dei loro compiti e per l'esercizio delle loro competenze. Prima dell'impiego dei membri delle squadre, lo Stato membro ospitante informa l'Agenzia in merito alle banche dati nazionali ed europee che possono essere consultate. L'Agenzia mette tali informazioni a disposizione di tutti gli Stati membri che partecipano alla missione.</p>\n<p class=\"oj-normal\">Tale consultazione è svolta nel rispetto del diritto dell'Unione in materia di protezione dei dati e della legislazione nazionale dello Stato membro ospitante in materia di protezione dei dati.</p>\n</div>"], [9, "<div>\n<p class=\"oj-normal\">9.   I provvedimenti di respingimento ai sensi dell'articolo 14 del regolamento (UE) 2016/399 sono adottati soltanto dalle guardie di frontiera dello Stato membro ospitante o dai membri delle squadre se autorizzati dallo Stato membro ospitante ad agire per proprio conto.</p>\n</div>"]]}, "41": {"label": "Articolo 41", "heading": "Documento di accreditamento", "anchor": "art_41", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   L'Agenzia, in collaborazione con lo Stato membro ospitante, rilascia ai membri delle squadre un documento, redatto nella lingua ufficiale dello Stato membro ospitante e in un'altra lingua ufficiale delle istituzioni dell'Unione, che identifica il titolare e ne attesta il diritto di svolgere i compiti e di esercitare le competenze di cui all'articolo 40. Nel documento figurano i seguenti dati di ciascun membro delle squadre:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">nome e nazionalità;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">grado o funzione;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">una fotografia digitale recente; nonché</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">i compiti che è autorizzato a svolgere durante la missione.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Il documento è restituito all'Agenzia al termine dell'operazione congiunta, del dispiegamento di una squadra di sostegno per la gestione della migrazione, del progetto pilota, dell'intervento rapido alle frontiere, dell'operazione di rimpatrio o dell'intervento di rimpatrio.</p>\n</div>"]]}, "42": {"label": "Articolo 42", "heading": "Responsabilità civile", "anchor": "art_42", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Quando i membri delle squadre operano in uno Stato membro ospitante, tale Stato membro è responsabile, conformemente alla sua normativa nazionale, degli eventuali danni da loro causati durante le loro operazioni.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Ove tali danni siano causati da negligenza grave o comportamento doloso, lo Stato membro ospitante può rivolgersi allo Stato membro di appartenenza per ottenere da quest'ultimo il rimborso di eventuali risarcimenti versati alle vittime o agli aventi diritto.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Fatto salvo l'esercizio dei suoi diritti nei confronti di terzi, ciascuno Stato membro rinuncia a chiedere allo Stato membro ospitante o a qualsiasi altro Stato membro il risarcimento dei danni subiti, a meno che il danno non sia dovuto a negligenza grave o comportamento doloso.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Eventuali controversie tra Stati membri quanto all'applicazione dei paragrafi 2 e 3 del presente articolo, che tali Stati non possano risolvere mediante negoziati tra loro, sono da essi sottoposte alla Corte di giustizia dell'Unione europea, ai sensi dell'articolo 273 TFUE.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   Fatto salvo l'esercizio dei suoi diritti nei confronti di terzi, l'Agenzia sostiene le spese connesse ai danni causati alle attrezzature dell'Agenzia durante la missione, a meno che il danno non sia dovuto a negligenza grave o comportamento doloso.</p>\n</div>"]]}, "43": {"label": "Articolo 43", "heading": "Responsabilità penale", "anchor": "art_43", "frags": [[null, "<p class=\"oj-normal\">Durante un'operazione congiunta, un progetto pilota, il dispiegamento di una squadra di sostegno per la gestione della migrazione, un intervento rapido alle frontiere, un'operazione di rimpatrio o un intervento di rimpatrio, i membri delle squadre sono assimilati al personale dello Stato membro ospitante per quanto riguarda i reati di cui potrebbero essere vittime o che potrebbero commettere.</p>"]]}, "44": {"label": "Articolo 44", "heading": "Sistemi di scambio di informazioni", "anchor": "art_44", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   L'Agenzia può adottare tutte le misure necessarie per agevolare lo scambio con la Commissione e gli Stati membri e, se del caso, con le pertinenti agenzie dell'Unione, di informazioni utili all'assolvimento dei suoi compiti. Essa sviluppa e gestisce un sistema informativo che permetta di scambiare informazioni classificate con detti interlocutori, e di scambiare i dati personali di cui agli articoli 45, 47, 48 e 49 del presente regolamento conformemente alla decisione 2013/488/UE del Consiglio (<span class=\"oj-super oj-note-tag\">32</span>) e della decisione (UE, Euratom) 2015/444 della Commissione (<span class=\"oj-super oj-note-tag\">33</span>).</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   L'Agenzia può adottare tutte le misure necessarie per semplificare lo scambio con l'Irlanda e il Regno Unito di informazioni utili all'assolvimento dei suoi compiti se esse sono inerenti alle attività cui tali paesi partecipano a norma dell'articolo 51 e dell'articolo 62, paragrafo 5.</p>\n</div>"]]}, "45": {"label": "Articolo 45", "heading": "Protezione dei dati", "anchor": "art_45", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Il regolamento (CE) n. 45/2001 si applica al trattamento dei dati personali da parte dell'Agenzia.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Il consiglio di amministrazione stabilisce le modalità di applicazione del regolamento (CE) n. 45/2001 da parte dell'Agenzia, anche in relazione al responsabile della protezione dei dati dell'Agenzia. Tali modalità sono stabilite previa consultazione del garante europeo della protezione dei dati.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Fatti salvi gli articoli 47, 48 e 49, l'Agenzia può trattare i dati personali per scopi amministrativi.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Fatto salvo l'articolo 48, sono vietate la trasmissione di dati personali trattati dall'Agenzia e la trasmissione ulteriore da parte degli Stati membri ad autorità di paesi terzi o a terze parti, comprese le organizzazioni internazionali, dei dati personali trattati dall'Agenzia nell'ambito del presente regolamento.</p>\n</div>"]]}, "46": {"label": "Articolo 46", "heading": "Finalità del trattamento dei dati personali", "anchor": "art_46", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   L'Agenzia può trattare i dati personali solo per i seguenti scopi:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">lo svolgimento dei suoi compiti di organizzazione e coordinamento di operazioni congiunte, progetti pilota, interventi rapidi alle frontiere e nell'ambito delle squadre di sostegno per la gestione della migrazione a norma dell'articolo 47;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">lo svolgimento dei suoi compiti di organizzazione e coordinamento di operazioni di rimpatrio e interventi di rimpatrio a norma dell'articolo 48;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">la facilitazione dello scambio di informazioni con gli Stati membri, l'EASO, Europol o Eurojust conformemente all'articolo 47;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">l'analisi del rischio da parte dell'Agenzia conformemente all'articolo 11;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">e)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">l'identificazione e la localizzazione delle navi nel quadro di EUROSUR conformemente all'articolo 49;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">f)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">compiti amministrativi.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Qualsiasi trattamento di dati personali di cui al paragrafo 1 rispetta il principio di proporzionalità ed è strettamente limitato ai dati personali necessari per le finalità di cui a tale paragrafo.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Uno Stato membro o un'altra agenzia dell'Unione che fornisca dati personali all'Agenzia stabilisce la o le finalità per cui tali dati sono trattati, conformemente al paragrafo 1. L'Agenzia può trattare tali dati personali per una finalità diversa altresì prevista dal paragrafo 1 solo se autorizzata dal fornitore delle informazioni.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Gli Stati membri e le altre agenzie dell'Unione possono indicare, al momento del trasferimento di dati personali, le eventuali limitazioni al loro accesso o uso, in termini generali o specifici, anche per quanto concerne il trasferimento, la cancellazione o la distruzione. Qualora tali limitazioni si rendano necessarie dopo il trasferimento dei dati personali, essi ne informano l'Agenzia. L'Agenzia si conforma a tali limitazioni.</p>\n</div>"]]}, "47": {"label": "Articolo 47", "heading": "Trattamento dei dati personali raccolti durante le operazioni congiunte, i progetti pilota e gli interventi rapidi alle frontiere e da parte delle squadre di sostegno per la gestione della migrazione", "anchor": "art_47", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   L'Agenzia tratta esclusivamente le seguenti categorie di dati personali raccolti e trasmessile dagli Stati membri o dal suo personale nel contesto di operazioni congiunte, progetti pilota e interventi rapidi alle frontiere, e da squadre di sostegno per la gestione della migrazione:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">dati personali riguardanti persone che sono sospettate, per motivi ragionevoli, dalle autorità competenti degli Stati membri di coinvolgimento nella criminalità transfrontaliera, compresi il traffico di migranti, la tratta di esseri umani o atti di terrorismo;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">dati personali relativi a persone che attraversano le frontiere esterne senza autorizzazione e i cui dati sono raccolti dalle squadre della guardia di frontiera e costiera europea, anche quando agiscono nel quadro delle squadre di sostegno per la gestione della migrazione;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">numeri di targa, numeri di identificazione dei veicoli, numeri di telefono o numeri di identificazione delle navi, che sono legati alle persone di cui alle lettere a) e b) e sono necessari per indagare e analizzare le rotte e i metodi utilizzati ai fini dell'immigrazione illegale e della criminalità transfrontaliera.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   I dati personali di cui al paragrafo 1 possono essere trattati dall'Agenzia nei seguenti casi:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">quando la trasmissione all'EASO, Europol o Eurojust è necessaria per un uso in conformità ai rispettivi mandati e in conformità dell'articolo 52;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">quando la trasmissione alle autorità degli Stati membri che sono responsabili del controllo delle frontiere, della migrazione, dell'asilo o delle attività di contrasto è necessaria per un uso in conformità alla legislazione nazionale e alle norme dell'Unione e nazionali in materia di protezione dei dati;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">quando ciò è necessario per l'elaborazione delle analisi dei rischi.</p>\n</td>\n</tr>\n</tbody>\n</table>\n<p class=\"oj-normal\">I dati personali riguardanti le persone di cui al paragrafo 1, lettera b), sono trasferiti alle autorità di contrasto solo in casi specifici e ove strettamente necessario al fine di prevenire, accertare, indagare o perseguire reati gravi.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   I dati personali sono cancellati subito dopo essere stati trasmessi all'EASO, Europol o Eurojust o alle autorità competenti degli Stati membri, o utilizzati per l'elaborazione dell'analisi del rischio. Il periodo di conservazione dei dati non supera in nessun caso i 90 giorni dalla data della loro raccolta. Nei risultati dell'analisi del rischio, i dati sono resi anonimi.</p>\n</div>"]]}, "48": {"label": "Articolo 48", "heading": "Trattamento dei dati personali nel contesto delle operazioni di rimpatrio e degli interventi di rimpatrio", "anchor": "art_48", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Quando svolge i suoi compiti di organizzazione e coordinamento delle operazioni di rimpatrio e conduce interventi di rimpatrio, l'Agenzia può trattare i dati personali dei rimpatriandi.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   I dati personali trattati dall'Agenzia sono strettamente limitati ai dati personali che sono necessari ai fini dell'operazione di rimpatrio o dell'intervento di rimpatrio.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   I dati personali sono cancellati non appena sia stato conseguito lo scopo per il quale sono stati raccolti, e al più tardi 30 giorni dopo il termine dell'operazione di rimpatrio o dell'intervento di rimpatrio.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Qualora uno Stato membro non trasmetta i dati personali dei rimpatriandi al vettore, l'Agenzia può procedere a tale trasmissione.</p>\n</div>"]]}, "49": {"label": "Articolo 49", "heading": "Trattamento dei dati personali nel quadro di EUROSUR", "anchor": "art_49", "frags": [[null, "<p class=\"oj-normal\">L'Agenzia può trattare dati personali ai sensi dell'articolo 13, paragrafo 2, del regolamento (UE) n. 1052/2013.</p>"]]}, "50": {"label": "Articolo 50", "heading": "Norme di sicurezza per la protezione delle informazioni classificate e delle informazioni sensibili non classificate", "anchor": "art_50", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   L'Agenzia applica le norme di sicurezza di cui alla decisione (UE, Euratom) 2015/444. Tali norme si applicano, fra l'altro, allo scambio, al trattamento e alla conservazione di informazioni classificate.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   L'Agenzia applica i principi di sicurezza adottati in relazione al trattamento delle informazioni sensibili non classificate quali definiti nella decisione (UE, Euratom) 2015/444 e da quest'ultima attuati. Il consiglio di amministrazione stabilisce le modalità di applicazione di tali principi di sicurezza.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   La classificazione non preclude la trasmissione delle informazioni al Parlamento europeo. Le informazioni e i documenti inviati al Parlamento europeo a norma del presente regolamento sono trasmessi e trattati conformemente alle norme riguardanti la trasmissione e il trattamento delle informazioni classificate applicabili tra il Parlamento europeo e la Commissione.</p>\n</div>"]]}, "51": {"label": "Articolo 51", "heading": "Cooperazione con l'Irlanda e il Regno Unito", "anchor": "art_51", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   L'Agenzia agevola la cooperazione operativa tra gli Stati membri e l'Irlanda e il Regno Unito in attività specifiche.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Il supporto che l'Agenzia offre in applicazione dell'articolo 8, paragrafo 1, lettere l), n) e o), comprende l'organizzazione di operazioni di rimpatrio di Stati membri a cui partecipino anche l'Irlanda o il Regno Unito o entrambi.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   L'applicazione del presente regolamento alle frontiere di Gibilterra è sospesa fino alla data di conclusione di un accordo sulla portata delle disposizioni in materia di attraversamento da parte delle persone delle frontiere esterne.</p>\n</div>"]]}, "52": {"label": "Articolo 52", "heading": "Collaborazione con le istituzioni, gli organi, gli organismi e i servizi dell'Unione e con le organizzazioni internazionali", "anchor": "art_52", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   L'Agenzia coopera con la Commissione, le altre istituzioni dell'Unione, il servizio europeo per l'azione esterna, l'EASO, Europol, l'Agenzia dell'Unione europea per i diritti fondamentali, Eurojust, il Centro satellitare dell'Unione europea, l'Agenzia europea per la sicurezza marittima e l'Agenzia europea di controllo della pesca, nonché con altri organi, organismi e servizi dell'Unione, nei settori contemplati dal presente regolamento, e in particolare con gli obiettivi di affrontare meglio le sfide migratorie nonché prevenire e individuare la criminalità transfrontaliera, come il traffico di migranti, la tratta di esseri umani e il terrorismo</p>\n<p class=\"oj-normal\">A tal fine, l'Agenzia può cooperare con organizzazioni internazionali competenti nei settori contemplati dal presente regolamento.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   La cooperazione di cui al paragrafo 1 si svolge nel quadro di accordi di lavoro conclusi con gli organismi di cui al paragrafo 1. Tali accordi devono essere approvati dalla Commissione in via preliminare. In ogni caso, l'Agenzia informa il Parlamento europeo in merito a tali accordi.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   L'Agenzia coopera con la Commissione, e se del caso, con gli Stati membri, nelle attività di cui al presente regolamento. Sebbene al di fuori dell'ambito di applicazione del presente regolamento, essa si impegna a tale cooperazione anche in attività relative al settore doganale, compresa la gestione del rischio, qualora tali attività possano favorirsi a vicenda. Tale cooperazione lascia impregiudicate le competenze esistenti della Commissione e degli Stati membri.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Le istituzioni, gli organi, gli organismi e i servizi dell'Unione e le organizzazioni internazionali di cui al paragrafo 1 usano le informazioni ricevute dall'Agenzia esclusivamente entro i limiti delle loro competenze e fintanto che rispettino i diritti fondamentali, compresi gli obblighi di protezione dei dati. La trasmissione ulteriore e ogni altra comunicazione di dati personali trattati dall'Agenzia ad altre istituzioni, organi, organismi e, servizi dell'Unione sono soggette ad accordi di lavoro specifici riguardanti lo scambio di dati personali, nonché alla previa approvazione del garante europeo della protezione dei dati. Qualsiasi trasferimento di dati personali da parte dell'Agenzia deve rispettare le disposizioni in materia di protezione dei dati di cui agli articoli da 45 a 49. Per quanto riguarda il trattamento delle informazioni classificate, tali accordi prevedono che l'istituzione, l'organo, l'organismo o il servizio dell'Unione o l'organizzazione internazionale interessati rispettino regole e norme di sicurezza equivalenti a quelle applicate dall'Agenzia.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   L'Agenzia può altresì, con l'accordo degli Stati membri interessati, invitare osservatori dalle istituzioni, organi, organismi e servizi dell'Unione o da organizzazioni internazionali a partecipare alle sue attività, in particolare alle operazioni congiunte e ai progetti pilota, alle analisi del rischio e alla formazione, nella misura in cui la loro presenza sia conforme agli obiettivi di tali attività, possa contribuire allo sviluppo della cooperazione e allo scambio di buone prassi e non comprometta la sicurezza complessiva delle attività. La partecipazione di tali osservatori alle analisi del rischio e alla formazione può avvenire solo con l'accordo degli Stati membri interessati. Per quanto riguarda le operazioni congiunte e i progetti pilota, la partecipazione di osservatori è subordinata all'accordo dello Stato membro ospitante. Norme dettagliate sulla partecipazione degli osservatori sono incluse nel piano operativo. Gli osservatori ricevono dall'Agenzia una formazione appropriata prima della loro partecipazione.</p>\n</div>"]]}, "53": {"label": "Articolo 53", "heading": "Cooperazione europea in materia di funzioni di guardia costiera", "anchor": "art_53", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   L'Agenzia, in collaborazione con l'Agenzia europea di controllo della pesca e l'Agenzia europea per la sicurezza marittima, sostiene le autorità nazionali che svolgono funzioni di guardia costiera a livello nazionale e dell'Unione e, ove opportuno, a livello internazionale:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">condividendo, integrando e analizzando le informazioni disponibili nei sistemi di segnalazione delle navi e altri sistemi di informazione ospitati da tali agenzie o accessibili alle stesse, in conformità delle rispettive basi giuridiche e fatta salva la titolarità dei dati da parte degli Stati membri;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">fornendo servizi di sorveglianza e di comunicazione mediante tecnologie avanzate, comprese infrastrutture terrestri e spaziali e sensori montati su qualsiasi tipo di piattaforma;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">potenziando le capacità mediante l'elaborazione di orientamenti e raccomandazioni e instaurando migliori prassi, nonché fornendo formazione e scambio di personale;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">migliorando lo scambio di informazioni e la cooperazione in materia di funzioni di guardia costiera, anche analizzando le sfide operative e i rischi emergenti nel settore marittimo;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">e)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">condividendo le capacità mediante la pianificazione e realizzando operazioni multifunzionali mediante la condivisione di risorse e altre capacità, nella misura in cui tali attività siano coordinate da dette agenzie e siano approvate dalle autorità competenti degli Stati membri interessati.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Le modalità dettagliate della cooperazione nelle funzioni di guardia costiera tra l'Agenzia, l'Agenzia europea di controllo della pesca e l'Agenzia europea per la sicurezza marittima sono stabilite in un accordo di lavoro, conformemente ai loro rispettivi mandati e alle regole finanziarie applicabili a tali agenzie. Tale accordo è approvato dal consiglio di amministrazione dell'Agenzia e dai consigli di amministrazione dell'Agenzia europea per la sicurezza marittima e dell'Agenzia europea di controllo della pesca.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   La Commissione, in stretta collaborazione con gli Stati membri, con l'Agenzia, con l'Agenzia europea per la sicurezza marittima e con l'Agenzia europea di controllo della pesca, mette a disposizione un manuale pratico sulla cooperazione europea nelle funzioni di guardia costiera. Tale manuale contiene orientamenti, raccomandazioni e migliori prassi per lo scambio di informazioni. La Commissione adotta il manuale sotto forma di raccomandazione.</p>\n</div>"]]}, "54": {"label": "Articolo 54", "heading": "Cooperazione con i paesi terzi", "anchor": "art_54", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Per quanto attiene alle sue attività e nella misura necessaria per l'espletamento dei suoi compiti, l'Agenzia agevola e incoraggia la cooperazione tecnica e operativa tra Stati membri e paesi terzi nel quadro della politica dell'Unione in materia di relazioni esterne, in particolare con riferimento alla protezione dei diritti fondamentali e al principio di non respingimento. L'Agenzia e gli Stati membri osservano il diritto dell'Unione, tra cui norme e standard che fanno parte dell'<span class=\"oj-italic\">acquis</span> dell'Unione, anche quando la cooperazione con i paesi terzi avviene nel territorio di detti paesi. L'instaurazione di una cooperazione con i paesi terzi consente di promuovere norme europee in materia di gestione delle frontiere e di rimpatrio.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   L'Agenzia può cooperare con le autorità di paesi terzi competenti per questioni contemplate nel presente regolamento, con il sostegno e di concerto con le delegazioni dell'Unione. Nel fare ciò agisce nel quadro della politica dell'Unione in materia di relazioni esterne, anche con riferimento alla protezione dei diritti fondamentali e al principio di non respingimento. Agisce inoltre nell'ambito di accordi di lavoro conclusi con tali autorità, conformemente al diritto dell'Unione e alle sue politiche. Tali accordi di lavoro precisano la portata, la natura e la finalità della cooperazione, e sono connessi alla gestione della cooperazione operativa. I progetti di accordi devono essere approvati dalla Commissione in via preliminare. L'Agenzia informa il Parlamento europeo prima della conclusione di un accordo di lavoro. L'Agenzia osserva il diritto dell'Unione, comprese le norme e gli standard che formano parte del suo <span class=\"oj-italic\">acquis</span>.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   In circostanze che richiedono una maggiore assistenza tecnica e operativa, l'Agenzia può coordinare la cooperazione operativa tra gli Stati membri e i paesi terzi in relazione alla gestione delle frontiere esterne. L'Agenzia deve avere la possibilità di effettuare interventi alle frontiere esterne che coinvolgono uno o più Stati membri e paesi terzi confinanti con almeno uno di tali Stati membri, previo accordo di tale paese terzo confinante, anche sul territorio di tale paese terzo. Le operazioni sono effettuate sulla base di un piano operativo assentito dallo Stato membro o dagli Stati membri confinanti con l'area operativa. Gli Stati membri partecipano alle operazioni congiunte sul territorio di un paese terzo su base volontaria. La Commissione è informata di tali attività.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Nei casi in cui è previsto che le squadre saranno utilizzate in un paese terzo in interventi nell'ambito dei quali i membri delle squadre disporranno di poteri esecutivi, o nel caso in cui altre attività in paesi terzi lo richiedano, l'Unione conclude con il paese terzo interessato un accordo sullo status. Tale accordo sullo status riguarda tutti gli aspetti necessari all'esecuzione delle attività. Stabilisce in particolare l'ambito dell'operazione, la responsabilità civile e penale e i compiti e le competenze dei membri delle squadre. L'accordo sullo status garantisce il pieno rispetto dei diritti fondamentali nel corso di tali operazioni.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   La Commissione predispone un modello di accordo sullo status per interventi sul territorio di paesi terzi.</p>\n</div>"], [6, "<div>\n<p class=\"oj-normal\">6.   L'Agenzia collabora con le autorità competenti dei paesi terzi nei casi di rimpatrio, anche per quanto riguarda l'acquisizione dei documenti di viaggio.</p>\n</div>"], [7, "<div>\n<p class=\"oj-normal\">7.   L'Agenzia può altresì, con l'accordo degli Stati membri interessati, invitare osservatori di paesi terzi a partecipare alle sue attività alle frontiere esterne di cui all'articolo 14, alle operazioni di rimpatrio di cui all'articolo 28, agli interventi di rimpatrio di cui all'articolo 33 e alla formazione di cui all'articolo 36, nella misura in cui la loro presenza sia conforme agli obiettivi di tali attività, possa contribuire allo sviluppo della cooperazione e allo scambio di buone prassi e non influisca sulla sicurezza complessiva di tali attività. La partecipazione di tali osservatori alle attività di cui agli articoli 14, 19, 28 e 36 può avvenire solo con l'accordo degli Stati membri interessati e la partecipazione alle attività di cui agli articoli 14 e 33 solo con l'accordo dello Stato membro ospitante. Norme dettagliate sulla partecipazione degli osservatori sono incluse nel piano operativo. Tali osservatori ricevono dall'Agenzia una formazione appropriata prima della loro partecipazione. Essi sono tenuti a osservare il codice di condotta dell'Agenzia mentre partecipano alle sue attività.</p>\n</div>"], [8, "<div>\n<p class=\"oj-normal\">8.   L'Agenzia partecipa all'attuazione di accordi internazionali conclusi dall'Unione con paesi terzi nel quadro della politica dell'Unione in materia di relazioni esterne e che riguardino i settori contemplati dal presente regolamento.</p>\n</div>"], [9, "<div>\n<p class=\"oj-normal\">9.   L'Agenzia può beneficiare del finanziamento dell'Unione ai sensi delle disposizioni dei pertinenti strumenti di sostegno alla politica dell'Unione in materia di relazioni esterne. Essa può varare e finanziare progetti di assistenza tecnica nei paesi terzi per le materie oggetto del presente regolamento.</p>\n</div>"], [10, "<div>\n<p class=\"oj-normal\">10.   Nel concludere accordi bilaterali con paesi terzi, gli Stati membri possono, in accordo con l'Agenzia, includere disposizioni riguardanti il ruolo e le competenze dell'Agenzia di cui al presente regolamento, in particolare per quanto riguarda l'esercizio dei poteri di esecuzione da parte dei membri delle squadre della guardia di frontiera e costiera europea dispiegate dall'Agenzia nelle operazioni congiunte, nei progetti pilota, negli interventi rapidi alle frontiere, nelle operazioni di rimpatrio o negli interventi di rimpatrio. Gli Stati membri comunicano tali disposizioni alla Commissione.</p>\n</div>"], [11, "<div>\n<p class=\"oj-normal\">11.   L'Agenzia informa il Parlamento europeo in merito alle attività espletate ai sensi del presente articolo. Essa include nelle sue relazioni annuali una valutazione della cooperazione con i paesi terzi.</p>\n</div>"]]}, "55": {"label": "Articolo 55", "heading": "Funzionari di collegamento nei paesi terzi", "anchor": "art_55", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   L'Agenzia può impiegare nei paesi terzi esperti appartenenti al proprio personale in qualità di funzionari di collegamento, i quali devono beneficiare della massima protezione nell'esercizio delle loro funzioni. Tali funzionari di collegamento appartengono alle reti di cooperazione locale o regionale dei funzionari di collegamento incaricati dell'immigrazione e degli esperti della sicurezza dell'Unione e degli Stati membri, compresa la rete istituita a norma del regolamento (CE) n. 377/2004 del Consiglio (<span class=\"oj-super oj-note-tag\">34</span>). I funzionari di collegamento sono impiegati unicamente nei paesi terzi le cui prassi in materia di gestione delle frontiere sono conformi alle norme minime di protezione dei diritti umani.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Nel quadro della politica dell'Unione in materia di relazioni esterne, è data priorità all'impiego di funzionari di collegamento nei paesi terzi che sono, secondo un'analisi del rischio, paesi di origine o transito di immigrazione illegale, L'Agenzia può ricevere funzionari di collegamento distaccati da tali paesi terzi secondo un criterio di reciprocità. Il consiglio di amministrazione adotta annualmente l'elenco delle priorità su proposta del direttore esecutivo. L'impiego di funzionari di collegamento è approvato dal consiglio di amministrazione.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Rientra tra i compiti dei funzionari di collegamento dell'Agenzia, nel rispetto del diritto dell'Unione e dei diritti fondamentali, instaurare e mantenere contatti con le autorità competenti dei paesi terzi presso i quali sono distaccati, per contribuire a prevenire e combattere l'immigrazione illegale e al rimpatrio di rimpatriandi. Tali funzionari di collegamento si coordinano strettamente con le delegazioni dell'Unione.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   La decisione di inviare funzionari di collegamento in paesi terzi è soggetta al previo parere della Commissione. Il Parlamento europeo è tenuto informato tempestivamente e in modo esaustivo su tali attività.</p>\n</div>"]]}, "56": {"label": "Articolo 56", "heading": "Natura giuridica e sede", "anchor": "art_56", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   L'Agenzia è un organismo dell'Unione. Essa ha personalità giuridica.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   L'Agenzia gode in tutti gli Stati membri della più ampia capacità giuridica riconosciuta alle persone giuridiche dai rispettivi diritti. In particolare, essa può acquisire o alienare beni mobili e immobili e può stare in giudizio.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   L'Agenzia è indipendente per quanto attiene all'adempimento del suo mandato tecnico e operativo.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   L'agenzia è rappresentata dal proprio direttore esecutivo.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   L'Agenzia ha sede a Varsavia (Polonia), fatta salva l'applicazione dell'articolo 57.</p>\n</div>"]]}, "57": {"label": "Articolo 57", "heading": "Accordo di sede", "anchor": "art_57", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Le necessarie disposizioni relative all'insediamento dell'Agenzia nello Stato membro che ne ospita la sede e alle strutture da questo messe a disposizione, nonché le norme specifiche applicabili in tale Stato membro al direttore esecutivo, al vicedirettore esecutivo, ai membri del consiglio di amministrazione, al personale dell'Agenzia e ai loro familiari sono stabilite in un accordo di sede fra l'Agenzia e lo Stato membro che ne ospita la sede.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   L'accordo di sede è concluso previa approvazione del consiglio di amministrazione, e al più tardi del 7 aprile 2017.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Lo Stato membro che ospita la sede garantisce le migliori condizioni possibili per il buon funzionamento dell'Agenzia, offrendo anche una scolarizzazione multilingue e a orientamento europeo e collegamenti di trasporto adeguati.</p>\n</div>"]]}, "58": {"label": "Articolo 58", "heading": "Personale", "anchor": "art_58", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Lo statuto dei funzionari («statuto dei funzionari») dell'Unione europea e il regime applicabile agli altri agenti dell'Unione europea («regime applicabile agli altri agenti»), di cui al regolamento (CEE, Euratom, CECA) n. 259/68 del Consiglio (<span class=\"oj-super oj-note-tag\">35</span>), e le regole adottate di comune accordo dalle istituzioni dell'Unione europea per l'applicazione di detto statuto e regime applicabile agli altri agenti si applicano al personale dell'Agenzia.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Ai fini dell'attuazione dell'articolo 12, dell'articolo 22 e dell'articolo 32, paragrafo 2, può essere nominato agente di coordinamento o funzionario di collegamento soltanto un membro del personale dell'Agenzia soggetto allo statuto dei funzionari o al titolo II del regime applicabile agli altri agenti. Ai fini dell'attuazione dell'articolo 20, paragrafo 11, possono essere designati per il distacco presso le squadre della guardia di frontiera e costiera europea soltanto guardie di frontiera o altro personale competente. L'Agenzia designa gli esperti nazionali che devono essere distaccati presso le squadre della guardia di frontiera e costiera europea in conformità del citato articolo.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Il consiglio di amministrazione adotta le necessarie disposizioni di esecuzione in accordo con la Commissione ai sensi dell'articolo 110 dello statuto dei funzionari.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Il consiglio di amministrazione può adottare disposizioni per consentire il distacco presso l'Agenzia di guardie di frontiera o altro personale competente degli Stati membri. Tali disposizioni tengono conto dei requisiti di cui all'articolo 20, paragrafo 11, in particolare del fatto che le guardie di frontiera o altro personale competente distaccati sono considerati membri delle squadre con i compiti e le competenze di cui all'articolo 40, e includono disposizioni sulle condizioni di impiego.</p>\n</div>"]]}, "59": {"label": "Articolo 59", "heading": "Privilegi e immunità", "anchor": "art_59", "frags": [[null, "<p class=\"oj-normal\">All'Agenzia e al suo personale si applica il protocollo sui privilegi e sulle immunità dell'Unione europea.</p>"]]}, "60": {"label": "Articolo 60", "heading": "Responsabilità", "anchor": "art_60", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   La responsabilità contrattuale dell'Agenzia è disciplinata dalla normativa applicabile al contratto interessato.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   La Corte di giustizia dell'Unione europea è competente a giudicare in virtù di clausole compromissorie contenute in un contratto concluso dall'Agenzia.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   In materia di responsabilità extracontrattuale l'Agenzia risarcisce, secondo i principi generali comuni agli ordinamenti degli Stati membri, i danni causati dai suoi servizi o dal suo personale nell'esercizio delle loro funzioni.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   La Corte di giustizia dell'Unione europea è competente a pronunciarsi in merito alle controversie relative al risarcimento dei danni di cui al paragrafo 3.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   La responsabilità personale nei confronti dell'Agenzia da parte del proprio personale è disciplinata dalle disposizioni dello statuto dei funzionari e del regime applicabile agli altri agenti a essi applicabili.</p>\n</div>"]]}, "61": {"label": "Articolo 61", "heading": "Struttura amministrativa e di gestione dell'Agenzia", "anchor": "art_61", "frags": [[null, "<p class=\"oj-normal\">La struttura amministrativa e di gestione dell'Agenzia comprende:</p>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">un consiglio di amministrazione;</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">un direttore esecutivo;</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">un forum consultivo; e</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">un responsabile dei diritti fondamentali.</p>\n</td>\n</tr>\n</tbody>\n</table>"]]}, "62": {"label": "Articolo 62", "heading": "Funzioni del consiglio di amministrazione", "anchor": "art_62", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Al consiglio di amministrazione compete l'adozione delle decisioni strategiche dell'Agenzia in conformità del presente regolamento.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Il consiglio di amministrazione:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">nomina il direttore esecutivo su proposta della Commissione ai sensi dell'articolo 69;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">nomina il vicedirettore esecutivo su proposta del direttore esecutivo ai sensi dell'articolo 69;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">adotta decisioni sulla realizzazione della valutazione delle vulnerabilità ai sensi dell'articolo 13, paragrafi 1 e 8, le decisioni che stabiliscono misure ai sensi dell'articolo 13, paragrafo 8 sono adottate a maggioranza dei due terzi dei membri aventi diritto di voto;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">adotta decisioni sull'istituzione di un modello comune di analisi integrata del rischio ai sensi dell'articolo 11, paragrafo 1;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">e)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">adotta decisioni sulla natura e sulle modalità dell'impiego di funzionari di collegamento negli Stati membri ai sensi dell'articolo 12, paragrafo 2;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">f)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">adotta una strategia operativa e tecnica per la gestione europea integrata delle frontiere ai sensi dell'articolo 3, paragrafo 2;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">g)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">adotta una decisione sui profili e sul numero complessivo delle guardie di frontiera o dell'altro personale competente da mettere a disposizione delle squadre della guardia di frontiera e costiera europea ai sensi dell'articolo 20, paragrafo 2;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">h)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">adotta, ai sensi dell'articolo 20, paragrafo 4, e a maggioranza di tre quarti dei membri con diritto di voto, una decisione sui profili e sul numero minimo delle guardie di frontiera o dell'altro personale competente corrispondenti a tali profili da mettere a disposizione della riserva di reazione rapida di squadre della guardia di frontiera e costiera europea;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">i)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">adotta una relazione annuale di attività sulle attività svolte dall'Agenzia nell'anno precedente e la trasmette entro il 1<span class=\"oj-super\">o</span> luglio al Parlamento europeo, al Consiglio, alla Commissione e alla Corte dei conti;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">j)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">entro il 30 novembre di ogni anno, tenuto conto del parere della Commissione, adotta, a maggioranza dei due terzi dei membri con diritto di voto, un documento unico di programmazione contenente la programmazione pluriennale dell'Agenzia e il suo programma di lavoro per l'anno successivo, e lo trasmette al Parlamento europeo, al Consiglio e alla Commissione;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">k)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">predispone procedure per l'adozione da parte del direttore esecutivo di decisioni in merito ai compiti tecnici e operativi dell'Agenzia;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">l)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">adotta, a maggioranza dei due terzi dei membri con diritto di voto, il bilancio annuale dell'Agenzia ed esercita altre funzioni in relazione al bilancio dell'Agenzia a norma della sezione 5 del presente capo;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">m)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">esercita autorità disciplinare nei confronti del direttore esecutivo e del vicedirettore esecutivo, di concerto con il direttore esecutivo;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">n)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">stabilisce il proprio regolamento interno;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">o)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">stabilisce la struttura organizzativa dell'Agenzia e adotta la politica relativa al personale dell'Agenzia;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">p)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">adotta una strategia antifrode, proporzionata al rischio di frode, tenendo conto dei costi e dei benefici delle misure da attuare;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">q)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">adotta norme di prevenzione e gestione dei conflitti di interesse in relazione ai suoi membri;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">r)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">ai sensi del paragrafo 8, esercita, nei confronti del personale dell'Agenzia, i poteri conferiti dallo statuto dei funzionari all'autorità che ha il potere di nomina e dal regime applicabile agli altri agenti all'autorità abilitata a concludere i contratti di assunzione («poteri dell'autorità che ha il potere di nomina»);</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">s)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">adotta idonee disposizioni di attuazione per dare effetto allo statuto dei funzionari e al regime applicabile agli altri agenti, conformemente all'articolo 110 dello statuto dei funzionari;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">t)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">assicura un seguito adeguato alle osservazioni e alle raccomandazioni risultanti dalle relazioni di audit e valutazioni interne ed esterne e dalle indagini dell'OLAF;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">u)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">adotta e aggiorna regolarmente i piani di comunicazione e divulgazione di cui all'articolo 8, paragrafo 3, secondo comma;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">v)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">nomina un contabile soggetto allo statuto dei funzionari e al regime applicabile agli altri agenti, che opera in piena indipendenza nell'esercizio delle sue funzioni;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">w)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">decide in merito a una metodologia comune per la valutazione delle vulnerabilità, inclusi i criteri oggettivi in virtù dei quali l'Agenzia effettua la valutazione delle vulnerabilità, la frequenza di tali valutazioni e come effettuare valutazioni consecutive delle vulnerabilità;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">x)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">decide in merito alla valutazione e al monitoraggio rafforzati di uno Stato membro di cui all'articolo 13, paragrafo 2;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">y)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">nomina il responsabile dei diritti fondamentali ai sensi dell'articolo 71, paragrafo 1;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">z)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">approva gli accordi di lavoro con i paesi terzi.</p>\n</td>\n</tr>\n</tbody>\n</table>\n<p class=\"oj-normal\">La relazione annuale di attività di cui al punto i) è pubblica.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Le proposte di decisione del consiglio di amministrazione di cui al paragrafo 2 relative ad attività specifiche dell'Agenzia da svolgere alle frontiere esterne di un determinato Stato membro, o nelle immediate vicinanze delle stesse, richiedono il voto favorevole alla loro adozione da parte del membro del consiglio di amministrazione che rappresenta detto Stato membro.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Il consiglio di amministrazione può consigliare il direttore esecutivo su qualsiasi questione legata allo sviluppo della gestione operativa delle frontiere esterne, comprese le attività in materia di ricerca.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   Su richiesta dell'Irlanda e/o del Regno Unito, il consiglio di amministrazione delibera in merito alla loro partecipazione ad attività specifiche.</p>\n<p class=\"oj-normal\">Il consiglio di amministrazione delibera caso per caso a maggioranza assoluta dei membri aventi diritto di voto. Nella sua decisione, il consiglio di amministrazione valuta se la partecipazione dell'Irlanda e/o del Regno Unito contribuisca alla realizzazione dell'attività in questione. Nella decisione è stabilito il contributo finanziario di detti paesi all'attività per la quale hanno presentato una richiesta di partecipazione.</p>\n</div>"], [6, "<div>\n<p class=\"oj-normal\">6.   Il consiglio di amministrazione trasmette ogni anno al Parlamento europeo e al Consiglio («autorità di bilancio») tutte le informazioni pertinenti all'esito delle procedure di valutazione svolte dall'Agenzia.</p>\n</div>"], [7, "<div>\n<p class=\"oj-normal\">7.   Il consiglio di amministrazione può istituire un comitato esecutivo ristretto che assista il consiglio stesso e il direttore esecutivo nel predisporre decisioni, programmi e attività che saranno adottati dal consiglio di amministrazione e che prenda certe decisioni provvisorie e urgenti per conto del consiglio di amministrazione, qualora necessario. Il comitato esecutivo non adotta decisioni che richiedono una maggioranza dei due terzi o dei tre quarti in seno al consiglio di amministrazione. Il consiglio di amministrazione può delegare determinati compiti chiaramente definiti al comitato esecutivo, in particolare quando ciò migliora l'efficacia dell'Agenzia. Il consiglio di amministrazione non può delegare al comitato esecutivo compiti collegati a decisioni che richiedono una maggioranza dei due terzi o dei tre quarti in seno al consiglio di amministrazione.8.</p>\n</div>"], [8, "<div>\n<p class=\"oj-normal\">8.   Il consiglio di amministrazione adotta, in conformità dell'articolo 110 dello statuto dei funzionari, una decisione basata sull'articolo 2, paragrafo 1, dello statuto dei funzionari e sull'articolo 6 del regime applicabile agli altri agenti, con cui delega al direttore esecutivo i poteri dell'autorità che ha il potere di nomina e stabilisce le condizioni di sospensione della delega di tali poteri. Il direttore esecutivo è autorizzato a subdelegare tali poteri.</p>\n<p class=\"oj-normal\">Qualora circostanze eccezionali lo richiedano, il consiglio di amministrazione può, mediante decisione, sospendere temporaneamente i poteri dell'autorità che ha il potere di nomina delegati al direttore esecutivo e quelli subdelegati da quest'ultimo. Può quindi esercitarli esso stesso o delegarli a uno dei suoi membri o a un membro del personale diverso dal direttore esecutivo.</p>\n</div>"]]}, "63": {"label": "Articolo 63", "heading": "Composizione del consiglio di amministrazione", "anchor": "art_63", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Fatto salvo il paragrafo 3, il consiglio di amministrazione è composto di un rappresentante di ciascuno Stato membro e di due rappresentanti della Commissione, tutti aventi diritto di voto. A tal fine ogni Stato membro nomina un membro del consiglio di amministrazione e un supplente per rappresentarlo in caso di assenza. La Commissione nomina due membri e i relativi supplenti. La durata del mandato è di quattro anni. Il mandato è rinnovabile.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   I membri del consiglio di amministrazione sono nominati in base al loro grado di esperienza e alle loro competenze di alto livello nel settore della cooperazione operativa in materia di gestione delle frontiere e di rimpatrio e alle loro pertinenti competenze gestionali, amministrative e di bilancio. Gli Stati membri e la Commissione hanno l'obiettivo di conseguire una rappresentanza di genere equilibrata nel consiglio di amministrazione.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   I paesi associati all'attuazione, all'applicazione e allo sviluppo dell'<span class=\"oj-italic\">acquis</span> di Schengen prendono parte alle attività dell'Agenzia. Ciascuno di essi ha un rappresentante e il relativo supplente nel consiglio di amministrazione. Si applicano gli accordi elaborati in base alle pertinenti disposizioni dei rispettivi accordi di associazione, che precisano la natura, la portata e le modalità particolareggiate della partecipazione di tali paesi al lavoro dell'Agenzia, comprese disposizioni sui contributi finanziari e sul personale.</p>\n</div>"]]}, "64": {"label": "Articolo 64", "heading": "Programmazione pluriennale e programma di lavoro annuale", "anchor": "art_64", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Entro il 30 novembre di ogni anno, il consiglio di amministrazione adotta un documento di programmazione contenente la programmazione pluriennale e il programma annuale per l'anno successivo basato su un progetto presentato dal direttore esecutivo che tiene conto del parere della Commissione e, per quanto riguarda la programmazione pluriennale, previa consultazione del Parlamento europeo. Il consiglio di amministrazione trasmette tale documento al Parlamento europeo, al Consiglio e alla Commissione.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Il documento di cui al paragrafo 1 diventa definitivo dopo l'approvazione definitiva del bilancio generale. Se necessario, è adeguato di conseguenza.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   La programmazione pluriennale definisce la programmazione strategica complessiva per il medio e lungo termine, compresi gli obiettivi, i risultati attesi, gli indicatori di risultato e la pianificazione delle risorse, compresi il bilancio pluriennale e il personale. La programmazione pluriennale definisce le aree strategiche di intervento e illustra le azioni necessarie per conseguire gli obiettivi. Essa comprende una strategia per le relazioni con i paesi terzi e le organizzazioni internazionali, nonché le azioni connesse a tale strategia.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   La programmazione pluriennale è attuata attraverso programmi di lavoro annuali e, se del caso, è aggiornata in base all'esito di una valutazione condotta ai sensi dell'articolo 81. Se del caso, le conclusioni di tali valutazioni sono tenute in considerazione anche nel programma di lavoro annuale per l'anno successivo.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   Il programma di lavoro annuale contiene una descrizione delle attività da finanziare, comprendente gli obiettivi dettagliati e i risultati attesi, compresi gli indicatori di risultato. Esso contiene inoltre un'indicazione delle risorse finanziarie e umane assegnate a ciascuna attività, in conformità ai principi di formazione del bilancio per attività e gestione per attività. Il programma di lavoro annuale è coerente con la programmazione pluriennale. Esso indica chiaramente i compiti aggiunti, modificati o soppressi rispetto all'esercizio finanziario precedente.</p>\n</div>"], [6, "<div>\n<p class=\"oj-normal\">6.   Il programma di lavoro annuale è adottato secondo il programma legislativo dell'Unione nei pertinenti settori della gestione delle frontiere esterne e del rimpatrio.</p>\n</div>"], [7, "<div>\n<p class=\"oj-normal\">7.   Quando, dopo l'adozione di un programma di lavoro annuale, all'Agenzia è affidato un nuovo compito, il consiglio di amministrazione modifica il programma di lavoro annuale.</p>\n</div>"], [8, "<div>\n<p class=\"oj-normal\">8.   Le modifiche sostanziali del programma di lavoro annuale sono adottate con la stessa procedura che si applica all'adozione del programma di lavoro annuale iniziale. Il consiglio di amministrazione può delegare al direttore esecutivo il potere di presentare modifiche non sostanziali del programma di lavoro annuale.</p>\n</div>"]]}, "65": {"label": "Articolo 65", "heading": "Presidenza del consiglio di amministrazione", "anchor": "art_65", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Il consiglio di amministrazione elegge un presidente e un vicepresidente scegliendoli tra i suoi membri aventi diritto di voto. Il presidente e il vicepresidente sono eletti a maggioranza di due terzi dei membri del consiglio di amministrazione aventi diritto di voto. Il vicepresidente sostituisce il presidente in caso di impedimento di quest'ultimo a svolgere le sue funzioni.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Il mandato del presidente e quello del vicepresidente scadono nel momento in cui cessa la loro appartenenza al consiglio di amministrazione. Nel rispetto della presente disposizione, la durata del mandato del presidente e del vicepresidente è di quattro anni. Il mandato è prorogabile una volta.</p>\n</div>"]]}, "66": {"label": "Articolo 66", "heading": "Riunioni", "anchor": "art_66", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Il consiglio di amministrazione si riunisce su convocazione del presidente.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Il direttore esecutivo partecipa alle deliberazioni del consiglio di amministrazione, senza diritto di voto.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Il consiglio di amministrazione tiene almeno due riunioni ordinarie all'anno. Si riunisce inoltre su istanza del presidente, su richiesta della Commissione o su richiesta di almeno un terzo dei suoi membri.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   L'Irlanda e il Regno Unito sono invitati a partecipare alle riunioni del consiglio di amministrazione.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   Il consiglio di amministrazione può invitare un rappresentante delle istituzioni, degli organi, degli organismi e dei servizi dell'Unione competenti.</p>\n</div>"], [6, "<div>\n<p class=\"oj-normal\">6.   Il consiglio di amministrazione può invitare a presenziare alle riunioni in veste di osservatore, conformemente al suo regolamento interno, qualsiasi altra persona il cui parere possa presentare un interesse.</p>\n</div>"], [7, "<div>\n<p class=\"oj-normal\">7.   I membri del consiglio di amministrazione possono essere assistiti da consiglieri o esperti, fatte salve le disposizioni del regolamento interno.</p>\n</div>"], [8, "<div>\n<p class=\"oj-normal\">8.   L'Agenzia provvede al segretariato del consiglio di amministrazione.</p>\n</div>"]]}, "67": {"label": "Articolo 67", "heading": "Votazioni", "anchor": "art_67", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Fatti salvi l'articolo 20, paragrafo 4, l'articolo 62, paragrafo 2, lettere c), j) e l), l'articolo 65, paragrafo 1, e l'articolo 69, paragrafi 2 e 4, il consiglio di amministrazione adotta le sue decisioni a maggioranza assoluta dei membri aventi diritto di voto.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Ogni membro dispone di un voto. In assenza di un membro il suo supplente può esercitare il diritto di voto. Il direttore esecutivo non partecipa al voto.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Il regolamento interno stabilisce disposizioni più dettagliate in materia di voto. Tale regolamento include le condizioni in cui un membro può agire per conto di un altro nonché, se del caso, le regole in materia di quorum.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   I rappresentanti dei paesi associati all'attuazione, all'applicazione e allo sviluppo dell'<span class=\"oj-italic\">acquis</span> di Schengen hanno diritti di voto limitati in corrispondenza con i rispettivi accordi. Al fine di consentire ai paesi associati di esercitare il loro diritto di voto, l'Agenzia indica in dettaglio l'ordine del giorno, individuando i punti per i quali è stato concesso un diritto di voto limitato.</p>\n</div>"]]}, "68": {"label": "Articolo 68", "heading": "Funzioni e poteri del direttore esecutivo", "anchor": "art_68", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   L'Agenzia è diretta dal suo direttore esecutivo, che è totalmente indipendente nell'espletamento delle sue funzioni. Ferme restando le rispettive competenze delle istituzioni dell'Unione e del consiglio di amministrazione, il direttore esecutivo non sollecita né accetta istruzioni da alcun governo o altro organismo.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Il Parlamento europeo o il Consiglio possono invitare il direttore esecutivo a riferire sull'esercizio delle sue funzioni. Ciò include informazioni sull'attuazione e sul monitoraggio della strategia in materia di diritti fondamentali, sulla relazione annuale di attività relativa alle attività dell'Agenzia nell'anno precedente, sul programma di lavoro per l'anno successivo e sulla programmazione pluriennale dell'Agenzia o su qualsiasi altra questione connessa alle attività dell'Agenzia. Il direttore esecutivo rilascia inoltre una dichiarazione dinanzi al Parlamento europeo, ove richiesto, e lo informa regolarmente.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Il direttore esecutivo è responsabile della preparazione e attuazione delle decisioni strategiche adottate dal consiglio di amministrazione e dell'adozione delle decisioni connesse alle attività operative dell'Agenzia in conformità del presente regolamento. Il direttore esecutivo è investito delle funzioni e dei poteri seguenti:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">proporre, preparare e attuare le decisioni strategiche e i programmi e le attività adottati dal consiglio di amministrazione nei limiti previsti dal presente regolamento, dalle relative norme di attuazione e dalla legislazione applicabile;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">adottare tutte le iniziative opportune, comprese l'adozione di istruzioni amministrative interne e la pubblicazione di comunicazioni, per garantire la gestione e il funzionamento quotidiani dell'Agenzia, conformemente al presente regolamento;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">preparare ogni anno il documento di programmazione e presentarlo al consiglio di amministrazione previa consultazione della Commissione;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">preparare ogni anno la relazione annuale di attività sulle attività dell'Agenzia e presentarla al consiglio di amministrazione;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">e)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">redigere un progetto di stato di previsione delle entrate e delle spese dell'Agenzia a norma dell'articolo 75 ed eseguire il bilancio a norma dell'articolo 76;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">f)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">delegare i suoi poteri ad altri membri del personale dell'Agenzia, nel rispetto delle regole da adottare secondo la procedura di cui all'articolo 62, paragrafo 2, lettera n);</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">g)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">adottare una raccomandazione relativa a misure in conformità dell'articolo 13, paragrafo 6, ivi comprese decisioni che propongono agli Stati membri di avviare e realizzare operazioni congiunte, interventi rapidi alle frontiere o un'altra azione di cui all'articolo 14, paragrafo 2;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">h)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">valutare, approvare e coordinare le proposte degli Stati membri relative alle operazioni congiunte o agli interventi rapidi alle frontiere conformemente all'articolo 15, paragrafo 3;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">i)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">valutare, approvare e coordinare le richieste degli Stati membri relative a operazioni congiunte di rimpatrio o a interventi di rimpatrio conformemente agli articoli 28 e 33;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">j)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">provvedere all'attuazione dei piani operativi di cui agli articoli 16 e 17 e all'articolo 33, paragrafo 4;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">k)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">valutare la richiesta di assistenza da parte delle squadre di sostegno per la gestione della migrazione presentata da uno Stato membro e valutare le necessità di quest'ultimo, di concerto con le pertinenti agenzie dell'Unione in conformità dell'articolo 18, paragrafo 2;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">l)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">assicurare l'attuazione delle decisioni del Consiglio di cui all'articolo 19, paragrafo 1;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">m)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">revocare il finanziamento delle attività in conformità dell'articolo 25;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">n)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">valutare i risultati delle attività in conformità dell'articolo 26;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">o)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">individuare il numero minimo di attrezzature tecniche necessarie a soddisfare il fabbisogno dell'Agenzia, in particolare per quanto riguarda la realizzazione di operazioni congiunte, il dispiegamento di squadre di sostegno per la gestione della migrazione, gli interventi rapidi alle frontiere, le operazioni e gli interventi di rimpatrio, in conformità dell'articolo 39, paragrafo 5;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">p)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">preparare un piano di azione a seguito delle conclusioni delle relazioni di audit e delle valutazioni interne ed esterne e delle indagini dell'OLAF e informare la Commissione, su base semestrale, nonché, periodicamente, il consiglio di amministrazione e il comitato esecutivo in merito ai progressi compiuti;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">q)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">tutelare gli interessi finanziari dell'Unione mediante l'applicazione di misure di prevenzione contro le frodi, la corruzione e qualsiasi altra attività illecita, attraverso controlli effettivi e, nel caso in cui siano riscontrate irregolarità, il recupero delle somme indebitamente corrisposte nonché, se del caso, l'applicazione di sanzioni amministrative e finanziarie effettive, proporzionate e dissuasive;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">r)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">elaborare una strategia antifrode dell'Agenzia e presentarla al consiglio di amministrazione per approvazione.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Il direttore esecutivo risponde delle sue attività al consiglio di amministrazione.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   Il direttore esecutivo è il rappresentante legale dell'Agenzia.</p>\n</div>"]]}, "69": {"label": "Articolo 69", "heading": "Nomina del direttore esecutivo e del vicedirettore esecutivo", "anchor": "art_69", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   La Commissione propone almeno tre candidati per il posto di direttore esecutivo sulla base di un elenco, successivamente alla pubblicazione del posto nella <span class=\"oj-italic\">Gazzetta ufficiale dell'Unione europea</span> e se del caso sulla stampa o su siti Internet.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Il direttore esecutivo è nominato dal consiglio di amministrazione sulla base del merito e della provata competenza di alto livello in materia amministrativa e gestionale, inclusa un'estesa e pertinente esperienza professionale in materia di gestione delle frontiere esterne e di rimpatri. Prima della nomina, i candidati proposti dalla Commissione sono invitati a rendere una dichiarazione dinanzi alla commissione o alle commissioni competenti del Parlamento europeo e a rispondere alle domande dei membri di tali commissioni.</p>\n<p class=\"oj-normal\">A seguito di tale dichiarazione il Parlamento europeo adotta un parere nel quale espone la sua opinione e può esprimere una preferenza per un candidato.</p>\n<p class=\"oj-normal\">Il consiglio di amministrazione nomina il direttore esecutivo tenendo conto di tale opinione. Il consiglio di amministrazione delibera alla maggioranza dei due terzi dei membri aventi diritto di voto.</p>\n<p class=\"oj-normal\">Se il consiglio di amministrazione decide di nominare un candidato diverso da quello per il quale il Parlamento europeo aveva espresso una preferenza, informa per iscritto il Parlamento europeo e il Consiglio del modo in cui è stato tenuto conto del parere del Parlamento europeo.</p>\n<p class=\"oj-normal\">Il consiglio di amministrazione, agendo su proposta della Commissione, ha potere di revoca del direttore esecutivo.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Il direttore esecutivo è affiancato da un vicedirettore esecutivo. In caso di assenza o indisponibilità del direttore esecutivo, il vicedirettore esecutivo ne fa le veci.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Il vicedirettore esecutivo è nominato dal consiglio di amministrazione su proposta del direttore esecutivo. È nominato sulla base del merito e della adeguata competenza in materia amministrativa e gestionale, compresa una pertinente esperienza professionale in materia di gestione delle frontiere esterne e di rimpatri. Il direttore esecutivo propone almeno tre candidati per il posto di vicedirettore esecutivo. Il consiglio d'amministrazione delibera alla maggioranza dei due terzi dei membri aventi diritto di voto.</p>\n<p class=\"oj-normal\">Il consiglio di amministrazione ha il potere di revocare il vicedirettore esecutivo secondo la procedura di cui al primo comma.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   La durata del mandato del direttore esecutivo è di cinque anni. Entro la fine di tale periodo, la Commissione effettua una valutazione che tiene conto dei risultati ottenuti dal direttore esecutivo, nonché dei compiti e delle sfide futuri dell'Agenzia.</p>\n</div>"], [6, "<div>\n<p class=\"oj-normal\">6.   Agendo su proposta della Commissione, la quale tiene conto della valutazione di cui al paragrafo 5, il consiglio di amministrazione può prorogare il mandato del direttore esecutivo una sola volta, per un periodo della durata massima di cinque anni.</p>\n</div>"], [7, "<div>\n<p class=\"oj-normal\">7.   Il mandato del vicedirettore esecutivo è di cinque anni. Esso può essere prorogato dal consiglio d'amministrazione una sola volta, per un periodo della durata massima di cinque anni.</p>\n</div>"]]}, "70": {"label": "Articolo 70", "heading": "Forum consultivo", "anchor": "art_70", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   L'Agenzia istituisce un forum consultivo che assiste il direttore esecutivo e il consiglio di amministrazione in questioni legate ai diritti fondamentali fornendo loro una consulenza indipendente.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   L'Agenzia invita l'EASO, l'Agenzia per i diritti fondamentali dell'Unione europea, l'Alto commissario delle Nazioni Unite per i rifugiati e altre pertinenti organizzazioni a partecipare al forum consultivo. Su proposta del direttore esecutivo, il consiglio di amministrazione decide in merito alla composizione del forum consultivo e alle modalità di trasmissione delle informazioni allo stesso. Il forum consultivo definisce i propri metodi di lavoro e stabilisce il proprio programma di lavoro previa consultazione del consiglio di amministrazione e del direttore esecutivo.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Il forum consultivo è consultato sull'ulteriore sviluppo e attuazione della strategia in materia di diritti fondamentali, sull'istituzione del meccanismo di denuncia, sui codici di condotta e sul programma comune di base per la formazione.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Il forum consultivo prepara una relazione annuale sulle sue attività. Tale relazione è resa pubblica.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   Fermi restando i compiti del responsabile dei diritti fondamentali, il forum consultivo dispone di un accesso effettivo a tutte le informazioni riguardanti il rispetto dei diritti fondamentali, anche mediante visite in loco effettuate durante le operazioni congiunte o gli interventi rapidi alle frontiere con l'accordo dello Stato membro ospitante nonché presso i punti di crisi o durante le operazioni di rimpatrio e gli interventi di rimpatrio.</p>\n</div>"]]}, "71": {"label": "Articolo 71", "heading": "Responsabile dei diritti fondamentali", "anchor": "art_71", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Un responsabile dei diritti fondamentali è nominato dal consiglio di amministrazione. È incaricato di contribuire alla strategia dell'Agenzia in materia di diritti fondamentali, di monitorarne la conformità a tali diritti e di promuovere il rispetto dei diritti fondamentali da parte dell'Agenzia. Il responsabile dei diritti fondamentali dispone delle qualifiche e dell'esperienza necessarie nel settore dei diritti fondamentali.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Il responsabile dei diritti fondamentali è indipendente nell'espletamento delle sue funzioni. Riferisce direttamente al consiglio di amministrazione e collabora con il forum consultivo. Il responsabile dei diritti fondamentali riferisce periodicamente contribuendo così al meccanismo per il monitoraggio dei diritti fondamentali.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Il responsabile dei diritti fondamentali è consultato in merito ai piani operativi redatti in conformità degli articoli 16, 17 e 28 e dell'articolo 33, paragrafo 4. Ha accesso a tutte le informazioni riguardanti il rispetto dei diritti fondamentali in relazione a tutte le attività dell'Agenzia.</p>\n</div>"]]}, "72": {"label": "Articolo 72", "heading": "Meccanismo di denuncia", "anchor": "art_72", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   L'Agenzia, in collaborazione con il responsabile dei diritti fondamentali, adotta le misure necessarie a istituire un meccanismo di denuncia in conformità al presente articolo, inteso a monitorare e assicurare il rispetto dei diritti fondamentali in tutte le attività dell'Agenzia.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Qualsiasi persona che sia direttamente interessata dalle azioni del personale che partecipa a un'operazione congiunta, a un progetto pilota, a un intervento rapido alle frontiere, al dispiegamento di squadre di sostegno per la gestione della migrazione, a un'operazione di rimpatrio o a un intervento di rimpatrio, e che ritenga di essere stata oggetto di una violazione dei suoi diritti fondamentali a seguito di tali azioni, o la parte che rappresenta tale persona, può presentare una denuncia per iscritto all'Agenzia.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Solo le denunce comprovate riguardanti violazioni concrete dei diritti fondamentali sono ricevibili.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Il responsabile dei diritti fondamentali è competente per la gestione delle denunce ricevute dall'Agenzia in conformità del diritto a una buona amministrazione. A tal fine, il responsabile dei diritti fondamentali esamina la ricevibilità delle denunce, registra le denunce ricevibili, inoltra le denunce ricevute al direttore esecutivo, trasmette le denunce riguardanti i membri delle squadre allo Stato membro di appartenenza, informa l'autorità o l'organo competenti in materia di diritti fondamentali di uno Stato membro nonché registra e assicura il seguito dato alla denuncia dall'Agenzia o da detto Stato membro.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   In conformità con il diritto a una buona amministrazione, se una denuncia è ricevibile, il denunciante è informato del fatto che la denuncia è stata registrata, che è stata avviata una valutazione e che riceverà una risposta non appena sarà disponibile. Se la denuncia è trasmessa alle autorità o agli organi nazionali, il denunciante ne riceve le informazioni di contatto. Se la denuncia non è ricevibile, il denunciante è informato dei motivi e riceve, ove possibile, informazioni sulle soluzioni alternative per affrontare il suo problema.</p>\n<p class=\"oj-normal\">Ogni decisione è redatta per iscritto ed è motivata.</p>\n</div>"], [6, "<div>\n<p class=\"oj-normal\">6.   Nel caso di una denuncia registrata nei confronti di un membro del personale dell'Agenzia, il direttore esecutivo assicura un seguito appropriato, in consultazione con il responsabile dei diritti fondamentali, comprese misure disciplinari se necessario. Il direttore esecutivo riferisce al responsabile dei diritti fondamentali, entro un termine stabilito, i risultati e il seguito dato dall'Agenzia alla denuncia, comprese le misure disciplinari se necessario.</p>\n<p class=\"oj-normal\">Se la denuncia è connessa a questioni relative alla protezione dei dati, il direttore esecutivo coinvolge il responsabile della protezione dei dati dell'Agenzia. Il responsabile dei diritti fondamentali e il responsabile della protezione dei dati concludono per iscritto un protocollo d'intesa, precisando la ripartizione dei loro compiti e la cooperazione in relazione alle denunce ricevute.</p>\n</div>"], [7, "<div>\n<p class=\"oj-normal\">7.   In caso di denuncia registrata nei confronti di una guardia di frontiera di uno Stato membro ospitante o di un membro delle squadre, compresi un membro distaccato della squadra o un esperto nazionale distaccato, lo Stato membro di appartenenza assicura un seguito appropriato, comprese, se necessarie, misure disciplinari o altre misure in conformità del diritto nazionale. Lo Stato membro interessato riferisce al responsabile dei diritti fondamentali i risultati e il seguito dato alla denuncia entro un determinato periodo e successivamente, se necessario, a intervalli regolari. L'Agenzia dà seguito alla questione se non riceve alcuna informazione in proposito dallo Stato membro interessato.</p>\n</div>"], [8, "<div>\n<p class=\"oj-normal\">8.   Qualora sia stata accertata una violazione dei diritti fondamentali o degli obblighi di protezione internazionale da parte di una guardia di frontiera o di un esperto nazionale distaccato, l'Agenzia può chiedere allo Stato membro di allontanare immediatamente la guardia di frontiera o l'esperto nazionale distaccato dall'attività dell'Agenzia o dalla riserva di reazione rapida.</p>\n</div>"], [9, "<div>\n<p class=\"oj-normal\">9.   Il responsabile dei diritti fondamentali riferisce al direttore esecutivo e al consiglio di amministrazione i risultati e il seguito dato alle denunce da parte dell'Agenzia e degli Stati membri. L'Agenzia include nella sua relazione annuale informazioni riguardanti il meccanismo di denuncia.</p>\n</div>"], [10, "<div>\n<p class=\"oj-normal\">10.   Il responsabile dei diritti fondamentali, in conformità delle disposizioni indicate nei paragrafi da 1 al 9 e dopo aver consultato il forum consultivo, elabora un modulo di denuncia standardizzato che richiede informazioni dettagliate e specifiche sull'asserita violazione di diritti fondamentali. Il responsabile dei diritti fondamentali elabora altresì qualsiasi altra regola specifica, se del caso. Il responsabile dei diritti fondamentali sottopone tale modulo e tali altre regole specifiche, se del caso, al direttore esecutivo e al consiglio di amministrazione.</p>\n<p class=\"oj-normal\">L'Agenzia provvede a che le informazioni inerenti alla possibilità di presentare denuncia e alla relativa procedura siano prontamente disponibili, anche per le persone vulnerabili. Il modulo di denuncia standardizzato è reso disponibile sul sito web dell'Agenzia e su supporto cartaceo nel corso di tutte le attività dell'Agenzia, nelle lingue che i cittadini di paesi terzi comprendono o che ragionevolmente si suppone comprendano. Il responsabile dei diritti fondamentali prende in considerazione le denunce anche quando non sono presentate mediante il modulo di denuncia standardizzato.</p>\n</div>"], [11, "<div>\n<p class=\"oj-normal\">11.   I dati personali contenuti in una denuncia devono essere gestiti e trattati dall'Agenzia, incluso il responsabile dei diritti fondamentali, in conformità del regolamento (CE) n. 45/2001 e dagli Stati membri a norma della direttiva 95/46/CE e della decisione quadro 2008/977/GAI.</p>\n<p class=\"oj-normal\">Ogniqualvolta un denunciante presenta una denuncia, si considera che esso acconsenta al trattamento dei suoi dati personali da parte dell'Agenzia e del responsabile dei diritti fondamentali ai sensi dell'articolo 5, lettera d), del regolamento (CE) n. 45/2001.</p>\n<p class=\"oj-normal\">Al fine di tutelare gli interessi dei denuncianti, le denunce devono essere trattate in maniera riservata dal responsabile dei diritti fondamentali conformemente al diritto nazionale e dell'Unione, a meno che il denunciante non rinunci esplicitamente al diritto alla riservatezza. Quando i denuncianti rinunciano al diritto alla riservatezza si considera che essi accettano che il responsabile dei diritti fondamentali o l'Agenzia ne divulghino l'identità alle autorità o agli organi competenti in relazione alla questione oggetto della denuncia, se del caso.</p>\n</div>"]]}, "73": {"label": "Articolo 73", "heading": "Regime linguistico", "anchor": "art_73", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   All'Agenzia si applicano le disposizioni del regolamento n. 1 (<span class=\"oj-super oj-note-tag\">36</span>).</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Fatte salve le decisioni prese in base all'articolo 342 TFUE, sia la relazione annuale di attività, sia il programma di lavoro di cui all'articolo 62, paragrafo 2, lettere i) e j), sono redatti in tutte le lingue ufficiali dell'Unione.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   I servizi di traduzione necessari per il funzionamento dell'Agenzia sono forniti dal Centro di traduzione degli organismi dell'Unione europea.</p>\n</div>"]]}, "74": {"label": "Articolo 74", "heading": "Trasparenza e comunicazione", "anchor": "art_74", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Quando tratta le domande di accesso ai documenti in suo possesso, l'Agenzia è soggetta al regolamento (CE) n. 1049/2001.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   L'Agenzia comunica informazioni di propria iniziativa sulle materie rientranti nell'ambito dei suoi compiti. Essa rende pubbliche le informazioni pertinenti, compresa la relazione annuale di attività di cui all'articolo 62, paragrafo 2, lettera i), e garantisce, fatto salvo l'articolo 50, in particolare, che il pubblico e qualsiasi parte interessata possano disporre rapidamente di informazioni obiettive, complete, affidabili e facilmente comprensibili riguardanti la sua attività. Nel fare ciò essa non rivela informazioni operative che, se rese pubbliche, comprometterebbero il conseguimento dell'obiettivo delle operazioni.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Il consiglio di amministrazione stabilisce le modalità pratiche per l'applicazione dei paragrafi 1 e 2.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Qualsiasi persona fisica o giuridica ha il diritto di rivolgersi per iscritto all'Agenzia in una delle lingue ufficiali dell'Unione. Ha inoltre diritto di ricevere una risposta nella medesima lingua.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   Le decisioni adottate dall'Agenzia ai sensi dell'articolo 8 del regolamento (CE) n. 1049/2001 possono costituire oggetto di denuncia presso il Mediatore europeo o di ricorso dinanzi alla Corte di giustizia dell'Unione europea alle condizioni, rispettivamente, di cui agli articoli 228 e 263 TFUE.</p>\n</div>"]]}, "75": {"label": "Articolo 75", "heading": "Bilancio", "anchor": "art_75", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Fatti salvi altri tipi di risorse, le entrate dell'agenzia comprendono:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">un contributo dell'Unione iscritto nel bilancio generale dell'Unione europea (sezione Commissione);</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">un contributo dei paesi terzi associati all'attuazione, all'applicazione e allo sviluppo dell'<span class=\"oj-italic\">acquis</span> di Schengen, secondo quanto previsto nei rispettivi accordi che stabiliscono il loro contributo finanziario;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">un finanziamento dell'Unione, sotto forma di accordi di delega o di sovvenzioni ad hoc ai sensi delle regole finanziarie dell'Agenzia di cui all'articolo 79 e delle disposizioni dei pertinenti strumenti di sostegno delle politiche dell'Unione;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">i compensi per i servizi forniti;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">e)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">ogni contributo volontario da parte degli Stati membri.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Le spese dell'Agenzia comprendono le proprie spese per l'amministrazione, le infrastrutture, il funzionamento e il personale.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Il direttore esecutivo predispone un progetto di stato di previsione delle entrate e delle spese dell'Agenzia per l'esercizio finanziario successivo, che comprende una tabella dell'organico, e lo trasmette al consiglio di amministrazione.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Le entrate e le spese risultano in pareggio.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   Sulla base del progetto di stato di previsione delle entrate e delle spese dell'Agenzia predisposto dal direttore esecutivo, il consiglio di amministrazione adotta un progetto di stato di previsione delle entrate e delle spese dell'Agenzia, che comprende una tabella provvisoria dell'organico. Il consiglio di amministrazione lo trasmette, assieme al progetto di documento unico di programmazione, al Parlamento europeo, al Consiglio e alla Commissione entro il 31 gennaio di ogni anno.</p>\n</div>"], [6, "<div>\n<p class=\"oj-normal\">6.   Il consiglio di amministrazione trasmette alla Commissione il progetto definitivo di stato di previsione delle entrate e delle spese, che include il progetto di tabella dell'organico corredato del programma preliminare di lavoro, entro il 31 marzo di ogni anno.</p>\n</div>"], [7, "<div>\n<p class=\"oj-normal\">7.   La Commissione trasmette lo stato di previsione all'autorità di bilancio unitamente al progetto di bilancio generale dell'Unione europea.</p>\n</div>"], [8, "<div>\n<p class=\"oj-normal\">8.   Sulla base dello stato di previsione, la Commissione iscrive nel progetto di bilancio generale dell'Unione europea le stime che ritiene necessarie per quanto concerne la tabella dell'organico e l'importo del contributo a carico del bilancio generale. Essa trasmette le stime all'autorità di bilancio ai sensi degli articoli 313 e 314 TFUE.</p>\n</div>"], [9, "<div>\n<p class=\"oj-normal\">9.   L'autorità di bilancio autorizza gli stanziamenti a titolo della sovvenzione destinata all'Agenzia.</p>\n<p class=\"oj-normal\">L'autorità di bilancio adotta la tabella dell'organico per l'Agenzia.</p>\n</div>"], [10, "<div>\n<p class=\"oj-normal\">10.   Il consiglio di amministrazione adotta il bilancio dell'Agenzia. Esso diventa definitivo dopo l'adozione definitiva del bilancio generale dell'Unione europea. Se del caso, è sottoposto agli opportuni adeguamenti.</p>\n</div>"], [11, "<div>\n<p class=\"oj-normal\">11.   Qualsiasi modifica del bilancio, inclusa la tabella dell'organico, segue la medesima procedura.</p>\n</div>"], [12, "<div>\n<p class=\"oj-normal\">12.   Ai progetti riguardanti gli immobili che possono avere implicazioni significative per il bilancio dell'Agenzia si applicano le disposizioni del regolamento delegato (UE) n. 1271/2013 della Commissione (<span class=\"oj-super oj-note-tag\">37</span>).</p>\n</div>"], [13, "<div>\n<p class=\"oj-normal\">13.   Per finanziare interventi rapidi alle frontiere e interventi di rimpatrio, il bilancio dell'Agenzia adottato dal consiglio di amministrazione comprende una riserva finanziaria operativa pari almeno al 4 % della dotazione prevista per le attività operative. Il 1<span class=\"oj-super\">o</span> ottobre di ogni anno dovrebbe essere ancora disponibile almeno un quarto della riserva per coprire i fabbisogni che dovessero presentarsi entro la fine dell'anno.</p>\n</div>"]]}, "76": {"label": "Articolo 76", "heading": "Esecuzione e controllo del bilancio", "anchor": "art_76", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Il direttore esecutivo esegue il bilancio dell'Agenzia.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Entro il 1<span class=\"oj-super\">o</span> marzo di un esercizio finanziario n + 1, il contabile dell'Agenzia comunica i conti provvisori per l'esercizio finanziario n al contabile della Commissione e alla Corte dei conti. Il contabile della Commissione consolida i conti provvisori delle istituzioni e degli organismi decentrati ai sensi dell'articolo 147 del regolamento (UE, Euratom) n. 966/2012 del Parlamento e del Consiglio (<span class=\"oj-super oj-note-tag\">38</span>).</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   L'Agenzia trasmette al Parlamento europeo, al Consiglio e alla Corte dei conti una relazione sulla gestione finanziaria e di bilancio per l'anno n entro il 31 marzo dell'anno n + 1.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Il contabile della Commissione trasmette alla Corte dei conti i conti provvisori dell'Agenzia per l'anno n, consolidati con i conti della Commissione, entro il 31 marzo dell'anno n + 1.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   Al ricevimento delle osservazioni formulate dalla Corte dei conti sui conti provvisori dell'Agenzia per l'anno n, ai sensi dell'articolo 148 del regolamento (UE, Euratom) n. 966/2012, il direttore esecutivo stabilisce i conti definitivi dell'Agenzia sotto la propria responsabilità e li trasmette al consiglio di amministrazione per parere.</p>\n</div>"], [6, "<div>\n<p class=\"oj-normal\">6.   Il consiglio di amministrazione formula un parere sui conti definitivi dell'Agenzia per l'anno n.</p>\n</div>"], [7, "<div>\n<p class=\"oj-normal\">7.   Entro il 1<span class=\"oj-super\">o</span> luglio dell'anno n + 1, il direttore esecutivo trasmette i conti definitivi, unitamente al parere del consiglio di amministrazione, al Parlamento europeo, al Consiglio, alla Commissione e alla Corte dei conti.</p>\n</div>"], [8, "<div>\n<p class=\"oj-normal\">8.   I conti definitivi per l'anno n sono pubblicati nella <span class=\"oj-italic\">Gazzetta ufficiale dell'Unione europea</span> entro il 15 novembre dell'anno n + 1.</p>\n</div>"], [9, "<div>\n<p class=\"oj-normal\">9.   Al più tardi il 30 settembre dell'anno n + 1, il direttore esecutivo invia alla Corte dei conti una risposta alle osservazioni di quest'ultima. Invia inoltre tale risposta al consiglio di amministrazione.</p>\n</div>"], [10, "<div>\n<p class=\"oj-normal\">10.   Il direttore esecutivo presenta al Parlamento europeo, su richiesta dello stesso e a norma dell'articolo 165, paragrafo 3, del regolamento (UE, Euratom) n. 966/2012, tutte le informazioni necessarie per il corretto svolgimento della procedura di discarico per l'esercizio n.</p>\n</div>"], [11, "<div>\n<p class=\"oj-normal\">11.   Il Parlamento europeo, su raccomandazione del Consiglio che delibera a maggioranza qualificata, dà discarico al direttore esecutivo, prima del 15 maggio dell'anno n + 2, per l'esecuzione del bilancio dell'esercizio n.</p>\n</div>"]]}, "77": {"label": "Articolo 77", "heading": "Lotta antifrode", "anchor": "art_77", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Per la lotta alle frodi, alla corruzione e ad altre attività illegali, si applicano senza restrizioni le disposizioni del regolamento (UE, Euratom) n. 883/2013. L'Agenzia aderisce all'accordo interistituzionale del 25 maggio 1999 relativo alle indagini interne svolte dall'Ufficio europeo per la lotta antifrode (OLAF) e adotta immediatamente le opportune disposizioni applicabili a tutti i dipendenti dell'Agenzia utilizzando i modelli riportati nell'allegato di tale accordo.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   La Corte dei conti ha il potere di revisione contabile, esercitabile sulla base di documenti e mediante ispezioni sul posto, su tutti i beneficiari di sovvenzioni, contraenti e subcontraenti che hanno ottenuto finanziamenti dell'Unione da parte dell'Agenzia.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   L'OLAF può svolgere indagini, compresi controlli e verifiche sul posto, conformemente alle disposizioni e procedure stabilite dal regolamento (UE, Euratom) n. 883/2013 e dal regolamento (Euratom, CE) n. 2185/96 del Consiglio (<span class=\"oj-super oj-note-tag\">39</span>), per accertare eventuali frodi, casi di corruzione o altre attività illecite lesive degli interessi finanziari dell'Unione in relazione a convenzioni o decisioni di sovvenzione o a contratti finanziati dall'Agenzia.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Fatti salvi i paragrafi 1, 2 e 3, gli accordi di cooperazione con paesi terzi e organizzazioni internazionali, i contratti, le convenzioni di sovvenzione e le decisioni di sovvenzione dell'Agenzia contengono disposizioni che autorizzano esplicitamente la Corte dei conti e l'OLAF a procedere a tali revisioni contabili e indagini conformemente alle loro rispettive competenze.</p>\n</div>"]]}, "78": {"label": "Articolo 78", "heading": "Prevenzione dei conflitti di interesse", "anchor": "art_78", "frags": [[null, "<p class=\"oj-normal\">L'Agenzia adotta norme interne che impongono ai membri dei suoi organi e del suo personale di evitare, durante il rapporto di impiego o il mandato, qualsiasi situazione suscettibile di causare un conflitto di interesse, e di segnalare tali situazioni.</p>"]]}, "79": {"label": "Articolo 79", "heading": "Disposizioni finanziarie", "anchor": "art_79", "frags": [[null, "<p class=\"oj-normal\">Le regole finanziarie applicabili all'Agenzia sono adottate dal consiglio di amministrazione previa consultazione della Commissione. Esse si discostano dal regolamento delegato (UE) n. 1271/2013 solo per esigenze specifiche di funzionamento dell'Agenzia e previo accordo della Commissione.</p>"]]}, "80": {"label": "Articolo 80", "heading": "Modifica del regolamento (UE) 2016/399", "anchor": "art_80", "frags": [[null, "<p class=\"oj-normal\">Nel regolamento (UE) 2016/399, all'articolo 29, il paragrafo 1 è sostituito dal seguente:</p>"], [null, "<div>\n<div>\n<p class=\"oj-normal\">«1.   In circostanze eccezionali in cui il funzionamento globale dello spazio senza controllo alle frontiere interne è messo a rischio a seguito di carenze gravi e persistenti nel controllo di frontiera alle frontiere esterne ai sensi dell'articolo 21 del presente regolamento oppure in conseguenza della mancata conformità di uno Stato membro alla decisione del Consiglio di cui all'articolo 19, paragrafo 1, del regolamento (UE) 2016/1624 del Parlamento europeo e del Consiglio (<span class=\"oj-super oj-note-tag\">*1</span>), e nella misura in cui tali circostanze costituiscono una minaccia grave per l'ordine pubblico o la sicurezza interna nello spazio senza controllo alle frontiere interne o su parti dello stesso, il controllo di frontiera alle frontiere interne può essere ripristinato in conformità del paragrafo 2 del presente articolo per una durata massima di sei mesi. Tale periodo può essere prorogato non più di tre volte, per ulteriori sei mesi al massimo, se le circostanze eccezionali perdurano.</p>\n</div>\n</div>"]]}, "81": {"label": "Articolo 81", "heading": "Valutazione", "anchor": "art_81", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Entro il 7 ottobre 2019, e successivamente ogni quattro anni, la Commissione richiede una valutazione esterna indipendente per esaminare, in particolare:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">i risultati conseguiti dall'Agenzia in relazione ai suoi obiettivi, al suo mandato e ai suoi compiti;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">l'incidenza, l'efficacia e l'efficienza dell'Agenzia e delle sue prassi di lavoro in relazione ai suoi obiettivi, al suo mandato e ai suoi compiti;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">l'attuazione della cooperazione europea in materia di funzioni di guardia costiera;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">l'eventuale necessità di modificare il mandato dell'Agenzia;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">e)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">le implicazioni finanziarie di tali modifiche.</p>\n</td>\n</tr>\n</tbody>\n</table>\n<p class=\"oj-normal\">La valutazione comporta un'analisi specifica del modo in cui sono stati osservati la Carta dei diritti fondamentali e il pertinente diritto dell'Unione nell'applicazione del presente regolamento.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   La Commissione trasmette la relazione di valutazione, corredata delle proprie conclusioni al riguardo, al Parlamento europeo, al Consiglio e al consiglio di amministrazione. Il consiglio di amministrazione può formulare raccomandazioni alla Commissione in merito a modifiche del presente regolamento. La relazione di valutazione e le conclusioni sulla relazione sono rese pubbliche.</p>\n</div>"]]}, "82": {"label": "Articolo 82", "heading": "Abrogazione", "anchor": "art_82", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   I regolamenti (CE) n. 2007/2004, (CE) n. 863/2007 e la decisione 2005/267/CE sono abrogati.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   I riferimenti all'abrogato regolamento (CE) n. 2007/2004 si intendono fatti al presente regolamento e si leggono secondo la tavola di concordanza di cui all'allegato II.</p>\n</div>"]]}, "83": {"label": "Articolo 83", "heading": "Entrata in vigore e applicabilità", "anchor": "art_83", "frags": [[null, "<p class=\"oj-normal\">Il presente regolamento entra in vigore il ventesimo giorno successivo alla pubblicazione nella <span class=\"oj-italic\">Gazzetta ufficiale dell'Unione europea</span>.</p>"], [null, "<p class=\"oj-normal\">L'articolo 20, paragrafi 5 e 6, e l'articolo 39, paragrafo 7, si applicano a decorrere dal 7 dicembre 2016. Gli articoli 29, 30, 31 e 32 si applicano a decorrere dal 7 gennaio 2017.</p>"]]}}, "recitals": {}};